// config/engine-citation-criteria.ts
//
// Chaque moteur IA a des critères de citation DIFFÉRENTS.
// Ce fichier définit les pondérations spécifiques par moteur.
// Le score AEO global pondère chaque moteur, mais chaque moteur
// a ses propres priorités.
//
// Ces critères sont utilisés par le scoring engine pour calculer
// le score par moteur ET pour générer des recommandations ciblées.

export interface EngineCitationProfile {
  engineId: string;
  name: string;
  // Pondération de chaque catégorie de critères (somme = 100)
  weights: {
    contentStructure: number;    // FAQ, headings, answer-first
    technicalSEO: number;       // Schema.org, meta, sitemap
    authority: number;           // E-E-A-T, backlinks, citations existantes
    freshness: number;           // Date de publication, mise à jour
    dataRichness: number;        // Stats, chiffres, tableaux, listes

