226→const generateTimeline = (): CrawlEvent[] => {
227→  const pages = ['/index.html', '/about', '/products', '/blog/ai-guide', '/faq', '/pricing', '/contact', '/blog/seo-tips', '/docs/api', '/team'];
228→  const bots = [
229→    { id: 'gptbot', name: 'GPTBot', icon: 'G' },
230→    { id: 'claudebot', name: 'ClaudeBot', icon: 'A' },
231→    { id: 'google-extended', name: 'Google-Extended', icon: 'G' },
232→    { id: 'perplexitybot', name: 'PerplexityBot', icon: 'P' },
233→    { id: 'chatgpt-user', name: 'ChatGPT-User', icon: 'C' },
234→    { id: 'anthropic-ai', name: 'anthropic-ai', icon: 'A' },
235→  ];
236→
237→  const events: CrawlEvent[] = [];
238→  const now = Date.now();
239→
240→  for (let i = 0; i < 20; i++) {
241→    const bot = bots[Math.floor(Math.random() * bots.length)];
242→    const minutesAgo = Math.floor(Math.random() * 120);
243→    const timestamp = new Date(now - minutesAgo * 60000);
244→    const statuses: ('success' | 'blocked' | 'error')[] = ['success', 'success', 'success', 'success', 'success', 'blocked', 'error'];
245→
246→    events.push({
247→      botId: bot.id,
248→      botName: bot.name,
249→      botIcon: bot.icon,
250→      timestamp: timestamp.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }),
251→      page: pages[Math.floor(Math.random() * pages.length)],
252→      status: statuses[Math.floor(Math.random() * statuses.length)],
253→      responseTime: Math.floor(Math.random() * 800) + 50,
254→    });
255→  }
256→
257→  return events.sort((a, b) => b.timestamp.localeCompare(a.timestamp));
258→};
