276→// Mini sparkline data generator for individual bot trend lines
277→const generateSparklineData = (crawlsWeek: number, trend: number) => {
278→  const points = 7;
279→  const data = [];
280→  const base = crawlsWeek / points;
281→  for (let i = 0; i < points; i++) {
282→    const trendFactor = trend >= 0
283→      ? 1 + (trend / 100) * (i / points)
284→      : 1 + (trend / 100) * (i / points);
285→    const noise = 0.7 + Math.random() * 0.6;
286→    data.push({
287→      day: `J${i + 1}`,
288→      crawls: Math.round(base * trendFactor * noise),
289→    });
290→  }
291→  return data;
292→};
