import React, { useState, useEffect } from 'react';
import {
  Bot, ArrowLeft, Activity, Eye, Clock, AlertTriangle, CheckCircle2,
  XCircle, ToggleLeft, ToggleRight, TrendingUp, FileText, RefreshCw,
  Shield, Zap, BarChart3, Globe, ChevronDown, ChevronUp, Bell
} from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, AreaChart, Area, CartesianGrid } from 'recharts';
import { useTranslation } from '../i18n';
import PageHeader from '../components/layout/PageHeader';

interface BotTrackingProps {
  onBack: () => void;
  user: { name: string; plan: string; credits: number } | null;
}

interface AIBot {
  id: string;
  name: string;
  agent: string;
  icon: string;
  color: string;
  bgColor: string;
  description: string;
  status: 'active' | 'inactive' | 'blocked';
  enabled: boolean;
  lastCrawl: string;
  crawlsToday: number;
  crawlsWeek: number;
  pagesVisited: number;
  frequency: string;
  trend: number;
}

interface CrawlEvent {
  botId: string;
  botName: string;
  botIcon: string;
  timestamp: string;
  page: string;
  status: 'success' | 'blocked' | 'error';
  responseTime: number;
}

interface BotAlert {
  id: string;
  type: 'warning' | 'info' | 'critical';
  message: string;
  botName: string;
  timestamp: string;
}

// Simulated AI bots data
const generateBots = (): AIBot[] => [
  {
    id: 'gptbot',
    name: 'GPTBot',
    agent: 'GPTBot',
    icon: 'G',
    color: 'text-purple-300',
    bgColor: 'bg-purple-500/10',
    description: 'OpenAI (ChatGPT)',
    status: 'active',
    enabled: true,
    lastCrawl: 'Il y a 12 min',
    crawlsToday: 47,
    crawlsWeek: 312,
    pagesVisited: 156,
    frequency: '~15 min',
    trend: 12,
  },
  {
    id: 'chatgpt-user',
    name: 'ChatGPT-User',
    agent: 'ChatGPT-User',
    icon: 'C',
    color: 'text-purple-300',
    bgColor: 'bg-purple-500/10',
    description: 'OpenAI Live Browsing',
    status: 'active',
    enabled: true,
    lastCrawl: 'Il y a 34 min',
    crawlsToday: 18,
    crawlsWeek: 89,
    pagesVisited: 42,
    frequency: '~45 min',
    trend: 5,
  },
  {
    id: 'claudebot',
    name: 'ClaudeBot',
    agent: 'ClaudeBot',
    icon: 'A',
    color: 'text-orange-400',
    bgColor: 'bg-orange-500/10',
    description: 'Anthropic (Claude)',
    status: 'active',
    enabled: true,
    lastCrawl: 'Il y a 8 min',
    crawlsToday: 52,
    crawlsWeek: 387,
    pagesVisited: 198,
    frequency: '~12 min',
    trend: 18,
  },
  {
    id: 'google-extended',
    name: 'Google-Extended',
    agent: 'Google-Extended',
    icon: 'G',
    color: 'text-blue-400',
    bgColor: 'bg-blue-500/10',
    description: 'Google Gemini / Vertex AI',
    status: 'active',
    enabled: true,
    lastCrawl: 'Il y a 3 min',
    crawlsToday: 78,
    crawlsWeek: 542,
    pagesVisited: 234,
    frequency: '~8 min',
    trend: 24,
  },
  {
    id: 'perplexitybot',
    name: 'PerplexityBot',
    agent: 'PerplexityBot',
    icon: 'P',
    color: 'text-purple-400',
    bgColor: 'bg-purple-500/10',
    description: 'Perplexity AI (Answer Engine)',
    status: 'active',
    enabled: true,
    lastCrawl: 'Il y a 22 min',
    crawlsToday: 31,
    crawlsWeek: 198,
    pagesVisited: 87,
    frequency: '~25 min',
    trend: 8,
  },
  {
    id: 'ccbot',
    name: 'CCBot',
    agent: 'CCBot',
    icon: 'CC',
    color: 'text-gray-500',
    bgColor: 'bg-gray-500/10',
    description: 'Common Crawl (Foundation LLMs)',
    status: 'active',
    enabled: true,
    lastCrawl: 'Il y a 2h',
    crawlsToday: 8,
    crawlsWeek: 45,
    pagesVisited: 312,
    frequency: '~3h',
    trend: -2,
  },
  {
    id: 'applebot',
    name: 'Applebot',
    agent: 'Applebot',
    icon: '',
    color: 'text-gray-300',
    bgColor: 'bg-gray-400/10',
    description: 'Apple Intelligence / Siri',
    status: 'inactive',
    enabled: true,
    lastCrawl: 'Il y a 6h',
    crawlsToday: 3,
    crawlsWeek: 21,
    pagesVisited: 45,
