            <div className="space-y-3">
              {filteredBots.map(bot => (
                <div key={bot.id} className="border border-[var(--border-subtle)] rounded-xl overflow-hidden transition-all hover:border-white/[0.06]">
                  {/* Bot Row */}
                  <div
                    className="flex items-center gap-4 p-4 cursor-pointer hover:bg-white/[0.03]/50 transition-colors"
                    onClick={() => setExpandedBot(expandedBot === bot.id ? null : bot.id)}
