                    {/* Expand */}
                    {expandedBot === bot.id ? <ChevronUp size={16} className="text-gray-500" /> : <ChevronDown size={16} className="text-gray-500" />}
                  </div>

                  {/* Expanded Detail */}
                  {expandedBot === bot.id && (
                    <div className="border-t border-[var(--border-subtle)] bg-[var(--bg-base)] p-4 animate-in fade-in duration-200">
