                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        <p className="text-[10px] text-gray-500 uppercase font-bold mb-2">Tendance de Crawl (7 jours)</p>
                        <ResponsiveContainer width="100%" height={48}>
                          <AreaChart data={generateSparklineData(bot.crawlsWeek, bot.trend)} margin={{ top: 2, right: 2, bottom: 2, left: 2 }}>
