              <Bell size={18} className="text-yellow-400" /> Alertes
            </h2>
            <div className="space-y-3">
              {alerts.map(alert => (
                <div key={alert.id} className={`p-3 rounded-2xl border ${
                  alert.type === 'critical' ? 'bg-red-500/5 border-red-500/20' :
