                     <CheckCircle2 size={14} className="text-blue-400 mt-0.5 shrink-0" />}
                    <div>
                      <p className="text-xs text-gray-300 leading-relaxed">{alert.message}</p>
                      <p className="text-[10px] text-gray-600 mt-1">{alert.timestamp}</p>
                    </div>
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Live Timeline */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
            <h2 className="text-lg font-bold text-white flex items-center gap-2 mb-4">
              <Activity size={18} className="text-purple-400" /> Timeline Live
              <span className="w-2 h-2 rounded-full bg-purple-300 animate-pulse"></span>
            </h2>
            <div className="space-y-2 max-h-[400px] overflow-y-auto custom-scrollbar pr-1">
              {timeline.slice(0, 15).map((event, idx) => (
                <div key={idx} className="flex items-center gap-3 p-2 rounded-xl hover:bg-white/[0.03]/50 transition-colors">
                  <span className="text-[10px] text-gray-600 w-10 shrink-0 font-mono">{event.timestamp}</span>
                  <div className={`w-6 h-6 rounded-md flex items-center justify-center text-[10px] font-bold ${
                    event.botId.includes('gpt') || event.botId.includes('chatgpt') ? 'bg-purple-500/10 text-purple-300' :
                    event.botId.includes('claude') || event.botId.includes('anthropic') ? 'bg-orange-500/10 text-orange-400' :
                    event.botId.includes('google') ? 'bg-blue-500/10 text-blue-400' :
                    'bg-purple-500/10 text-purple-400'
                  }`}>
                    {event.botIcon}
                  </div>
                  <div className="flex-1 min-w-0">
                    <p className="text-xs text-gray-300 truncate">{event.page}</p>
                  </div>
                  <div className="flex items-center gap-2">
                    <span className="text-[10px] text-gray-600">{event.responseTime}ms</span>
                    {event.status === 'success' ? (
                      <CheckCircle2 size={12} className="text-purple-300" />
                    ) : event.status === 'blocked' ? (
                      <XCircle size={12} className="text-red-400" />
                    ) : (
                      <AlertTriangle size={12} className="text-yellow-400" />
                    )}
                  </div>
                </div>
              ))}
            </div>
          </div>

          {/* Top Pages */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
            <h2 className="text-lg font-bold text-white flex items-center gap-2 mb-4">
              <Globe size={18} className="text-blue-400" /> Pages les Plus Crawlées
            </h2>
            <div className="space-y-3">
              {[
                { page: '/index.html', crawls: 234, pct: 100 },
                { page: '/blog/ai-guide', crawls: 187, pct: 80 },
                { page: '/faq', crawls: 156, pct: 67 },
                { page: '/products', crawls: 132, pct: 56 },
                { page: '/about', crawls: 98, pct: 42 },
                { page: '/pricing', crawls: 76, pct: 32 },
              ].map((item, idx) => (
                <div key={idx}>
                  <div className="flex justify-between text-xs mb-1">
                    <span className="text-gray-300 font-mono truncate mr-2">{item.page}</span>
                    <span className="text-gray-500 shrink-0">{item.crawls}</span>
                  </div>
                  <div className="h-1.5 bg-white/[0.03] rounded-full overflow-hidden">
                    <div className="h-full bg-primary/40 rounded-full" style={{ width: `${item.pct}%` }}></div>
                  </div>
                </div>
              ))}
            </div>
          </div>
        </div>
      </div>
    </div>
  );
};

export default BotTracking;

