  8→  onNavigate: (view: any) => void;
  9→  history?: AnalysisResult[];
 10→  megaStatus?: MegaGenerationStatus;
 11→}
 12→
 13→// IDs of tools that are pre-generable via mega-generation
 14→const PRE_GENERABLE_TOOLS: Record<string, string> = {
