 33→    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: t.reputation.positive },
 34→    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: t.reputation.neutral },
 35→    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: t.reputation.negative },
 36→  };
 37→
 38→  const [step, setStep] = useState<'form' | 'results'>('form');
