 71→  const handleScan = async () => {
 72→    if (!brandName || !industry) {
 73→      alert(locale === 'en' ? 'Please fill in the brand name and industry.' : locale === 'es' ? 'Por favor, rellena el nombre de la marca y el sector.' : 'Veuillez remplir le nom de la marque et le secteur.');
 74→      return;
