148→            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
149→            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
150→          </svg>
151→          <div className="absolute inset-0 flex items-center justify-center">
152→            <span className="text-2xl font-bold text-white">{score}</span>
153→          </div>
154→        </div>
155→        <span className="text-xs text-gray-500 mt-2">{label}</span>
156→      </div>
157→    );
158→  };
159→
160→  return (
161→    <div className="page-enter">
162→      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />
163→
164→      {/* Header */}
165→      <div className="flex items-center gap-4 mb-10">
