 60→// Animated number hook for smooth credit transitions
 61→const useAnimatedNumber = (value: number, duration = 600) => {
 62→  const [display, setDisplay] = useState(value);
 63→  const prevValue = useRef(value);
 64→  useEffect(() => {
 65→    if (prevValue.current === value) return;
 66→    const start = prevValue.current;
 67→    const diff = value - start;
 68→    const startTime = performance.now();
 69→    const animate = (now: number) => {
 70→      const progress = Math.min((now - startTime) / duration, 1);
 71→      const eased = 1 - Math.pow(1 - progress, 3);
 72→      setDisplay(Math.round(start + diff * eased));
 73→      if (progress < 1) requestAnimationFrame(animate);
 74→    };
 75→    requestAnimationFrame(animate);
 76→    prevValue.current = value;
 77→  }, [value, duration]);
 78→  return display;
 79→};
