239→        } else {
240→            if (analysisDate < projectCreationDates.get(hostname)!) {
241→                projectCreationDates.set(hostname, analysisDate);
242→            }
243→        }
244→    });
245→
246→    let count = 0;
247→    projectCreationDates.forEach((creationDate) => {
248→        if (creationDate >= billingCycleStart) {
