669→          {/* Low Credits Warning Banner */}
670→          {user && user.credits <= 10 && !lowCreditsDismissed && currentView !== 'credits' && currentView !== 'recharge' && (
671→            <div className="mb-4 px-4 py-2.5 rounded-xl bg-amber-500/10 border border-amber-500/20 flex items-center gap-3">
672→              <AlertTriangle size={16} className="text-amber-400 shrink-0" />
673→              <p className="text-sm text-amber-300 flex-1">Crédits bientôt épuisés ({user.credits} restants). <button onClick={() => navigateTo('credits')} className="underline font-semibold hover:text-amber-200">Recharger maintenant</button></p>
674→              <button onClick={() => setLowCreditsDismissed(true)} className="text-amber-400/60 hover:text-amber-300"><X size={14} /></button>
675→            </div>
676→          )}
677→
678→          <Suspense fallback={
679→            <div className="space-y-6">
680→              <div className="flex items-center justify-between">
681→                <div className="h-8 w-48 skeleton-shimmer rounded-xl" />
682→                <div className="h-10 w-36 skeleton-shimmer rounded-full" />
683→              </div>
684→              <div className="grid grid-cols-1 md:grid-cols-4 gap-4">
685→                {[1,2,3,4].map(i => <div key={i} className="h-28 skeleton-shimmer rounded-2xl border border-white/[0.04]" />)}
686→              </div>
687→              <div className="h-64 skeleton-shimmer rounded-2xl border border-white/[0.04]" />
688→            </div>
689→          }>
690→            <div key={pageKey} className="animate-in fade-in slide-in-from-bottom-2 duration-300">
691→              {renderPage()}
692→            </div>
693→          </Suspense>
694→
695→          {/* Floating Action Button — New Audit */}
696→          {user && (
697→            <button
698→              onClick={() => navigateTo('new-analysis')}
699→              className="fixed bottom-8 right-6 z-40 w-14 h-14 rounded-full bg-gradient-to-br from-blue-500 to-purple-600 shadow-xl shadow-blue-900/40 flex items-center justify-center text-white hover:scale-110 hover:shadow-2xl transition-all duration-300 group"
700→              title="Nouvel Audit AEO"
701→            >
