  const [expandedBot, setExpandedBot] = useState<string | null>(null);
  const [filterStatus, setFilterStatus] = useState<'all' | 'active' | 'inactive' | 'blocked'>('all');
  const [isRefreshing, setIsRefreshing] = useState(false);

  const totalCrawlsToday = bots.reduce((sum, b) => sum + b.crawlsToday, 0);
  const totalCrawlsWeek = bots.reduce((sum, b) => sum + b.crawlsWeek, 0);
  const activeBots = bots.filter(b => b.status === 'active').length;
  const totalPages = bots.reduce((sum, b) => sum + b.pagesVisited, 0);

  const filteredBots = bots.filter(b => {
    if (filterStatus === 'all') return true;
    return b.status === filterStatus;
  });

  const toggleBot = (botId: string) => {
    setBots(prev => prev.map(b => {
      if (b.id !== botId) return b;
      const newEnabled = !b.enabled;
      return {
        ...b,
        enabled: newEnabled,
        status: newEnabled ? (b.crawlsToday > 0 ? 'active' : 'inactive') : 'blocked',
      };
    }));
  };

  const handleRefresh = () => {
    setIsRefreshing(true);
    setTimeout(() => {
      setBots(generateBots());
      setIsRefreshing(false);
    }, 1500);
  };

  const statusBadge = (status: string) => {
    switch (status) {
      case 'active':
        return <span className="flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold bg-purple-500/20 text-purple-300"><span className="w-2 h-2 rounded-full bg-purple-300 animate-pulse"></span>Actif</span>;
      case 'inactive':
        return <span className="flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold bg-yellow-500/20 text-yellow-400"><span className="w-2 h-2 rounded-full bg-yellow-400"></span>Inactif</span>;
      case 'blocked':
        return <span className="flex items-center gap-1.5 px-2.5 py-1 rounded-full text-xs font-bold bg-red-500/20 text-red-400"><span className="w-2 h-2 rounded-full bg-red-400"></span>Bloqué</span>;
      default:
        return null;
    }
  };

  return (
    <div className="page-enter">
      <PageHeader title="Tracking Bots IA" description="Activation et suivi des bots IA" />

      {/* Header */}
      <div className="flex flex-col md:flex-row justify-between items-start md:items-center mb-8 gap-4">
        <div className="flex items-center gap-4">
          <button onClick={onBack} className="p-2 hover:bg-purple-500/10 rounded-full transition-colors">
            <ArrowLeft size={20} className="text-gray-500" />
          </button>
          <div>
            <div className="flex items-center gap-3">
              <h1 className="text-3xl font-bold text-white">{(t as any).botTracking?.title || 'Activation & Suivi des Bots IA'}</h1>
              <span className="bg-purple-500/10 text-purple-400 text-xs font-bold px-3 py-1 rounded-full border border-primary/20 flex items-center gap-1">
                <Activity size={12} /> LIVE
              </span>
            </div>
            <p className="text-gray-500 text-sm mt-1">{(t as any).botTracking?.subtitle || 'Surveillez et contrôlez l\'accès des crawlers IA à votre site'}</p>
          </div>
        </div>
        <button
          onClick={handleRefresh}
          disabled={isRefreshing}
          className="flex items-center gap-2 px-4 py-2.5 bg-white/[0.03] border border-white/[0.06] hover:bg-purple-500/10 rounded-2xl text-sm text-gray-300 transition-all"
        >
          <RefreshCw size={16} className={isRefreshing ? 'animate-spin' : ''} />
          {isRefreshing ? 'Actualisation...' : 'Actualiser'}
        </button>
      </div>

      {/* KPI Cards */}
      <div className="grid grid-cols-2 md:grid-cols-4 gap-4 mb-8">
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
          <div className="flex items-center gap-2 mb-3">
            <div className="p-2 bg-purple-500/10 rounded-full"><Bot size={18} className="text-purple-300" /></div>
            <span className="text-xs text-gray-500 uppercase font-bold">Bots Actifs</span>
          </div>
          <p className="text-3xl font-bold text-white">{activeBots}<span className="text-gray-500 text-lg">/{bots.length}</span></p>
        </div>
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
          <div className="flex items-center gap-2 mb-3">
            <div className="p-2 bg-blue-500/10 rounded-full"><Eye size={18} className="text-blue-400" /></div>
            <span className="text-xs text-gray-500 uppercase font-bold">Crawls Aujourd'hui</span>
          </div>
          <p className="text-3xl font-bold text-white">{totalCrawlsToday}</p>
          <p className="text-xs text-purple-300 mt-1">+14% vs hier</p>
        </div>
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
          <div className="flex items-center gap-2 mb-3">
            <div className="p-2 bg-purple-500/10 rounded-full"><BarChart3 size={18} className="text-purple-400" /></div>
            <span className="text-xs text-gray-500 uppercase font-bold">Crawls Semaine</span>
          </div>
          <p className="text-3xl font-bold text-white">{totalCrawlsWeek.toLocaleString()}</p>
          <p className="text-xs text-purple-300 mt-1">+8% vs semaine précédente</p>
        </div>
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5">
          <div className="flex items-center gap-2 mb-3">
            <div className="p-2 bg-orange-500/10 rounded-full"><FileText size={18} className="text-orange-400" /></div>
            <span className="text-xs text-gray-500 uppercase font-bold">Pages Indexées</span>
          </div>
          <p className="text-3xl font-bold text-white">{totalPages}</p>
          <p className="text-xs text-gray-500 mt-1">sur l'ensemble des bots</p>
        </div>
      </div>

      {/* Main Grid */}
      <div className="grid lg:grid-cols-3 gap-6 mb-8">

        {/* Bot List (2/3) */}
        <div className="lg:col-span-2 space-y-6">

          {/* Activity Chart */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
            <div className="flex justify-between items-center mb-6">
              <h2 className="text-lg font-bold text-white flex items-center gap-2">
                <TrendingUp size={18} className="text-purple-400" /> Activité de Crawl (24h)
              </h2>
              <div className="flex gap-2">
                {['GPTBot', 'ClaudeBot', 'Gemini'].map((name, i) => (
                  <span key={name} className={`text-[10px] px-2 py-0.5 rounded-full ${i === 0 ? 'bg-purple-500/20 text-purple-300' : i === 1 ? 'bg-orange-500/20 text-orange-400' : 'bg-blue-500/20 text-blue-400'}`}>{name}</span>
                ))}
              </div>
            </div>
            <ResponsiveContainer width="100%" height={160}>
              <BarChart data={HOURLY_CHART_DATA} margin={{ top: 4, right: 4, bottom: 0, left: 4 }}>
                <CartesianGrid strokeDasharray="3 3" stroke="rgba(255,255,255,0.04)" vertical={false} />
                <XAxis
                  dataKey="hour"
                  tick={{ fill: '#4b5563', fontSize: 10 }}
                  tickLine={false}
                  axisLine={false}
                  interval={2}
                />
                <YAxis hide />
                <Tooltip
                  contentStyle={{
                    backgroundColor: 'rgba(0,0,0,0.9)',
                    border: '1px solid rgba(255,255,255,0.1)',
                    borderRadius: '12px',
                    color: '#fff',
                    fontSize: '12px',
                    padding: '8px 12px',
                  }}
                  itemStyle={{ color: '#c4b5fd' }}
                  labelStyle={{ color: '#9ca3af', fontSize: '11px', marginBottom: '4px' }}
                  cursor={{ fill: 'rgba(124, 58, 237, 0.08)' }}
                  formatter={(value: number) => [`${value} crawls`, 'Activité']}
                />
                <Bar dataKey="crawls" fill="#7c3aed" radius={[2, 2, 0, 0]} />
              </BarChart>
            </ResponsiveContainer>
          </div>

          {/* Bot Filter + List */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
            <div className="flex flex-col sm:flex-row justify-between items-start sm:items-center mb-6 gap-4">
              <h2 className="text-lg font-bold text-white flex items-center gap-2">
                <Shield size={18} className="text-purple-400" /> Bots IA Surveillés
              </h2>
              <div className="flex gap-2">
                {(['all', 'active', 'inactive', 'blocked'] as const).map(status => (
                  <button
                    key={status}
                    onClick={() => setFilterStatus(status)}
                    className={`px-3 py-1.5 rounded-full text-xs font-bold transition-all ${
                      filterStatus === status
                        ? 'bg-purple-500/20 text-purple-400 border border-primary/30'
                        : 'bg-white/[0.03] text-gray-500 border border-[var(--border-subtle)] hover:bg-purple-500/10'
                    }`}
                  >
                    {status === 'all' ? 'Tous' : status === 'active' ? 'Actifs' : status === 'inactive' ? 'Inactifs' : 'Bloqués'}
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-3">
