import React, { useState, useEffect } from 'react';
import {
  Bot, ArrowLeft, Activity, Eye, Clock, AlertTriangle, CheckCircle2,
  XCircle, ToggleLeft, ToggleRight, TrendingUp, FileText, RefreshCw,
  Shield, Zap, BarChart3, Globe, ChevronDown, ChevronUp, Bell
} from 'lucide-react';
import { BarChart, Bar, XAxis, YAxis, Tooltip, ResponsiveContainer, AreaChart, Area, CartesianGrid } from 'recharts';
import PageHeader from '../components/layout/PageHeader';

interface BotTrackingProps {
  onBack: () => void;
  user: { name: string; plan: string; credits: number } | null;
}

interface AIBot {
  id: string;
  name: string;
  agent: string;
  icon: string;
  color: string;
  bgColor: string;
  description: string;
  status: 'active' | 'inactive' | 'blocked';
  enabled: boolean;
  lastCrawl: string;
  crawlsToday: number;
  crawlsWeek: number;
  pagesVisited: number;
  frequency: string;
  trend: number;
}

interface CrawlEvent {
  botId: string;
  botName: string;
  botIcon: string;
  timestamp: string;
  page: string;
  status: 'success' | 'blocked' | 'error';
  responseTime: number;
}

interface BotAlert {
  id: string;
  type: 'warning' | 'info' | 'critical';
  message: string;
  botName: string;
  timestamp: string;
}

// Simulated AI bots data
const generateBots = (): AIBot[] => [
  {
    id: 'gptbot',
    name: 'GPTBot',
    agent: 'GPTBot',
    icon: 'G',
    color: 'text-purple-300',
    bgColor: 'bg-purple-500/10',
    description: 'OpenAI (ChatGPT)',
    status: 'active',
    enabled: true,
