const generateTimeline = (): CrawlEvent[] => {
  const pages = ['/index.html', '/about', '/products', '/blog/ai-guide', '/faq', '/pricing', '/contact', '/blog/seo-tips', '/docs/api', '/team'];
  const bots = [
    { id: 'gptbot', name: 'GPTBot', icon: 'G' },
    { id: 'claudebot', name: 'ClaudeBot', icon: 'A' },
    { id: 'google-extended', name: 'Google-Extended', icon: 'G' },
    { id: 'perplexitybot', name: 'PerplexityBot', icon: 'P' },
    { id: 'chatgpt-user', name: 'ChatGPT-User', icon: 'C' },
    { id: 'anthropic-ai', name: 'anthropic-ai', icon: 'A' },
  ];

  const events: CrawlEvent[] = [];
  const now = Date.now();

  for (let i = 0; i < 20; i++) {
    const bot = bots[Math.floor(Math.random() * bots.length)];
    const minutesAgo = Math.floor(Math.random() * 120);
    const timestamp = new Date(now - minutesAgo * 60000);
    const statuses: ('success' | 'blocked' | 'error')[] = ['success', 'success', 'success', 'success', 'success', 'blocked', 'error'];

    events.push({
      botId: bot.id,
      botName: bot.name,
      botIcon: bot.icon,
      timestamp: timestamp.toLocaleTimeString('fr-FR', { hour: '2-digit', minute: '2-digit' }),
      page: pages[Math.floor(Math.random() * pages.length)],
      status: statuses[Math.floor(Math.random() * statuses.length)],
      responseTime: Math.floor(Math.random() * 800) + 50,
    });
  }

  return events.sort((a, b) => b.timestamp.localeCompare(a.timestamp));
};

