              </button>
              <button onClick={() => handleDownload(`${brandName}-${selectedType}.md`, result.content)} className="p-2.5 border border-white/[0.06] bg-white/[0.03] rounded-full hover:bg-white/[0.08] transition-colors" title={t.common.download}>
