import React, { useState } from 'react';
import { User, ContentWriterInput, GeneratedContent, ContentVertical, ContentType } from '../types';
import { generateContent } from '../services/content_writer';
import { ArrowLeft, Feather, Copy, Download, Check, Loader2, RefreshCw, ShoppingBag, Cloud, Building, UtensilsCrossed, Heart, DollarSign, Scale, GraduationCap, Globe, FileText, Layout, Mail, Tag, Share2, Newspaper, BookOpen, Send, Sparkles } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const VERTICAL_ICONS: { id: ContentVertical; icon: React.ElementType; color: string }[] = [
  { id: 'ecommerce', icon: ShoppingBag, color: 'text-pink-400' },
  { id: 'saas', icon: Cloud, color: 'text-blue-400' },
  { id: 'immobilier', icon: Building, color: 'text-purple-400' },
  { id: 'restauration', icon: UtensilsCrossed, color: 'text-orange-400' },
  { id: 'sante', icon: Heart, color: 'text-red-400' },
  { id: 'finance', icon: DollarSign, color: 'text-purple-300' },
  { id: 'juridique', icon: Scale, color: 'text-purple-400' },
  { id: 'education', icon: GraduationCap, color: 'text-cyan-400' },
  { id: 'general', icon: Globe, color: 'text-gray-500' },
];

const CONTENT_TYPE_ICONS: { id: ContentType; icon: React.ElementType; cost: number }[] = [
  { id: 'product_description', icon: FileText, cost: 2 },
  { id: 'landing_page', icon: Layout, cost: 3 },
  { id: 'sales_email', icon: Mail, cost: 2 },
  { id: 'meta_tags', icon: Tag, cost: 1 },
  { id: 'social_post', icon: Share2, cost: 1 },
  { id: 'press_release', icon: Newspaper, cost: 2 },
  { id: 'case_study', icon: BookOpen, cost: 3 },
  { id: 'newsletter', icon: Send, cost: 2 },
];

const VERTICAL_LABELS: Record<string, string> = {
  ecommerce: 'E-commerce', saas: 'SaaS', immobilier: 'Immobilier', restauration: 'Restauration',
  sante: 'Santé', finance: 'Finance', juridique: 'Juridique', education: 'Éducation', general: 'Général',
};
const CONTENT_TYPE_LABELS: Record<string, string> = {
  product_description: 'Fiche Produit', landing_page: 'Landing Page', sales_email: 'Email de Prospection',
  meta_tags: 'Kit Meta Tags', social_post: 'Posts Sociaux', press_release: 'Communiqué de Presse',
  case_study: 'Étude de Cas', newsletter: 'Newsletter',
};
const TONE_LABELS: Record<string, string> = {
  professionnel: 'Professionnel', decontracte: 'Décontracté', autoritaire: 'Autoritaire',
  empathique: 'Empathique', technique: 'Technique',
};

const ContentWriter: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const [step, setStep] = useState<'vertical' | 'type' | 'form' | 'result'>('vertical');
  const [selectedVertical, setSelectedVertical] = useState<ContentVertical>('general');
  const [selectedType, setSelectedType] = useState<ContentType>('product_description');
  const [isGenerating, setIsGenerating] = useState(false);
  const [result, setResult] = useState<GeneratedContent | null>(null);
  const [copied, setCopied] = useState(false);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [productOrService, setProductOrService] = useState('');
  const [targetAudience, setTargetAudience] = useState('');
  const [tone, setTone] = useState<ContentWriterInput['tone']>('professionnel');
  const [language, setLanguage] = useState<'fr' | 'en' | 'es'>('fr');
  const [additionalContext, setAdditionalContext] = useState('');

  const currentTypeCost = CONTENT_TYPE_ICONS.find(ct => ct.id === selectedType)?.cost || 2;

  const getVerticalLabel = (id: ContentVertical) => VERTICAL_LABELS[id] || id;
  const getContentTypeLabel = (id: ContentType) => CONTENT_TYPE_LABELS[id] || id;
  const getToneLabel = (id: string) => TONE_LABELS[id] || id;

  const handleGenerate = async () => {
    if (!brandName || !productOrService || !targetAudience) {
      alert('Veuillez remplir tous les champs obligatoires.');
      return;
    }

    const canProceed = onDeductCredits(currentTypeCost);
    if (!canProceed) return;

    setIsGenerating(true);
    try {
      const output = await generateContent({
        vertical: selectedVertical,
        contentType: selectedType,
        brandName,
        brandUrl: brandUrl || undefined,
        productOrService,
        targetAudience,
        tone,
        language,
        additionalContext: additionalContext || undefined,
      });
      setResult(output);
      setStep('result');
    } catch (error) {
      console.error(error);
      alert('Erreur lors de la génération.');
    } finally {
      setIsGenerating(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownload = (filename: string, content: string) => {
    const blob = new Blob([content], { type: 'text/markdown' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = filename;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  const handleRegenerate = () => {
    setResult(null);
    setStep('form');
  };

  const ScoreRingMini = ({ score }: { score: number }) => {
    const color = score >= 75 ? '#a855f7' : score >= 50 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 28;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="relative w-20 h-20">
        <svg className="w-20 h-20 -rotate-90" viewBox="0 0 64 64">
          <circle cx="32" cy="32" r="28" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="4" />
          <circle cx="32" cy="32" r="28" fill="none" stroke={color} strokeWidth="4" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
        </svg>
        <div className="absolute inset-0 flex items-center justify-center">
          <span className="text-lg font-bold text-white">{score}</span>
        </div>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Rédacteur IA" description="Génération de contenu optimisé AEO" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-rose-500/10 rounded-2xl">
          <Feather size={32} className="text-rose-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">AI Content Writer B2B</h1>
          <p className="text-gray-500">Générez du contenu optimisé AEO pour votre vertical métier</p>
        </div>
        <span className="ml-auto bg-rose-500/10 text-rose-400 text-xs font-bold px-3 py-1 rounded-full border border-rose-500/20 flex items-center gap-1">
          <Sparkles size={12} /> FRAMEWORK C.I.T.E.D.B.Y.
        </span>
      </div>

      {/* Step 1: Select Vertical */}
      {step === 'vertical' && (
        <div>
          <h2 className="text-xl font-bold text-white mb-6">1. {t.contentWriter.step1Title}</h2>
          <div className="grid grid-cols-2 sm:grid-cols-3 gap-4">
            {VERTICAL_ICONS.map(v => (
              <button
                key={v.id}
                onClick={() => { setSelectedVertical(v.id); setStep('type'); }}
                className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6 flex flex-col items-center gap-3 hover:bg-white/[0.03] hover:border-white/[0.12] transition-all group"
              >
                <v.icon size={32} className={`${v.color} group-hover:scale-110 transition-transform`} />
                <span className="text-sm font-bold text-gray-300 group-hover:text-white">{getVerticalLabel(v.id)}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Step 2: Select Content Type */}
      {step === 'type' && (
        <div>
          <div className="flex items-center gap-2 mb-2">
            <button onClick={() => setStep('vertical')} className="text-gray-500 hover:text-white text-sm">&larr; Vertical</button>
            <span className="text-gray-600 text-sm">/</span>
            <span className="text-rose-400 text-sm font-medium">{getVerticalLabel(selectedVertical)}</span>
          </div>
          <h2 className="text-xl font-bold text-white mb-6">2. {t.contentWriter.step2Title}</h2>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            {CONTENT_TYPE_ICONS.map(ct => (
              <button
                key={ct.id}
                onClick={() => { setSelectedType(ct.id); setStep('form'); }}
                className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-5 flex flex-col items-center gap-3 hover:bg-white/[0.03] hover:border-white/[0.12] transition-all group"
              >
                <ct.icon size={28} className="text-rose-400 group-hover:scale-110 transition-transform" />
                <span className="text-xs font-bold text-gray-300 group-hover:text-white text-center">{getContentTypeLabel(ct.id)}</span>
                <span className="text-[10px] text-gray-500">{ct.cost} {t.common.credits}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Step 3: Form */}
      {step === 'form' && (
        <div>
          <div className="flex items-center gap-2 mb-2">
            <button onClick={() => setStep('type')} className="text-gray-500 hover:text-white text-sm">&larr; Type</button>
            <span className="text-gray-600 text-sm">/</span>
            <span className="text-rose-400 text-sm font-medium">{getContentTypeLabel(selectedType)}</span>
          </div>
          <h2 className="text-xl font-bold text-white mb-6">3. {t.contentWriter.step3Title}</h2>
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6 space-y-5">
            <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
              <div>
                <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.brandName} *</label>
                <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-white/[0.03] border border-white/[0.06] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              </div>
              <div>
                <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.brandUrl} ({t.common.optional})</label>
                <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-white/[0.03] border border-white/[0.06] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              </div>
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.productOrService} *</label>
              <input value={productOrService} onChange={e => setProductOrService(e.target.value)} placeholder="Ex: AEO optimization platform" className="w-full bg-white/[0.03] border border-white/[0.06] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.targetAudience} *</label>
              <input value={targetAudience} onChange={e => setTargetAudience(e.target.value)} placeholder="Ex: B2B Marketing Directors" className="w-full bg-white/[0.03] border border-white/[0.06] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div className="grid grid-cols-1 md:grid-cols-3 gap-5">
              <div>
                <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.tone}</label>
                <select value={tone} onChange={e => setTone(e.target.value as any)} className="w-full bg-white/[0.03] border border-white/[0.06] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm">
                  {['professionnel', 'decontracte', 'autoritaire', 'empathique', 'technique'].map(toneId => (
                    <option key={toneId} value={toneId}>{getToneLabel(toneId)}</option>
                  ))}
                </select>
              </div>
              <div>
                <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.language}</label>
                <select value={language} onChange={e => setLanguage(e.target.value as 'fr' | 'en' | 'es')} className="w-full bg-white/[0.03] border border-white/[0.06] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm">
                  <option value="fr">{t.contentWriter.contentLanguages.fr}</option>
                  <option value="en">{t.contentWriter.contentLanguages.en}</option>
                  <option value="es">{t.contentWriter.contentLanguages.es}</option>
                </select>
              </div>
              <div className="flex items-end">
                <div className="bg-rose-500/10 border border-rose-500/20 rounded-2xl px-4 py-3 text-center w-full">
                  <span className="text-xs text-gray-500">{t.common.score}</span>
                  <span className="block text-lg font-bold text-rose-400">{currentTypeCost} GTO</span>
                </div>
              </div>
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.contentWriter.additionalContext} ({t.common.optional})</label>
              <textarea value={additionalContext} onChange={e => setAdditionalContext(e.target.value)} rows={3} placeholder="..." className="w-full bg-white/[0.03] border border-white/[0.06] rounded-2xl p-3 text-white focus:border-purple-500/50 outline-none text-sm resize-none" />
            </div>
            <button
              onClick={handleGenerate}
              disabled={isGenerating || !brandName || !productOrService || !targetAudience}
              className="w-full btn-gradient text-white font-bold py-3.5 rounded-full hover:opacity-90 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
            >
              {isGenerating ? <><Loader2 size={18} className="animate-spin" /> {t.common.loading}</> : <><Feather size={18} /> {t.contentWriter.generateContent}</>}
            </button>
          </div>
        </div>
      )}

      {/* Step 4: Result */}
      {step === 'result' && result && (
        <div>
          <div className="flex items-center gap-2 mb-6">
            <button onClick={handleRegenerate} className="text-gray-500 hover:text-white text-sm">&larr; {t.contentWriter.modifyBrief}</button>
          </div>

          {/* Score + Meta */}
          <div className="flex items-center gap-6 mb-8 bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
            <ScoreRingMini score={result.aeoScore} />
            <div className="flex-1">
              <h3 className="text-lg font-bold text-white">{result.title}</h3>
              {result.metaDescription && <p className="text-sm text-gray-500 mt-1">{result.metaDescription}</p>}
            </div>
            <div className="flex gap-2">
              <button onClick={() => handleCopy(result.content)} className="p-2.5 border border-white/[0.06] bg-white/[0.03] rounded-full hover:bg-white/[0.08] transition-colors" title={t.common.copy}>
