                className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6 flex flex-col items-center gap-3 hover:bg-white/[0.03] hover:border-white/[0.12] transition-all group"
              >
                <v.icon size={32} className={`${v.color} group-hover:scale-110 transition-transform`} />
                <span className="text-sm font-bold text-gray-300 group-hover:text-white">{getVerticalLabel(v.id)}</span>
              </button>
            ))}
          </div>
        </div>
      )}

      {/* Step 2: Select Content Type */}
      {step === 'type' && (
        <div>
          <div className="flex items-center gap-2 mb-2">
            <button onClick={() => setStep('vertical')} className="text-gray-500 hover:text-white text-sm">&larr; Vertical</button>
            <span className="text-gray-600 text-sm">/</span>
            <span className="text-rose-400 text-sm font-medium">{getVerticalLabel(selectedVertical)}</span>
          </div>
          <h2 className="text-xl font-bold text-white mb-6">2. Type de contenu</h2>
          <div className="grid grid-cols-2 sm:grid-cols-4 gap-4">
            {CONTENT_TYPE_ICONS.map(ct => (
              <button
                key={ct.id}
