                  <Copy size={12} /> {t.common.copy}
                </button>
              </div>
              <pre className="text-xs text-purple-300 bg-black/40 rounded-xl p-4 overflow-x-auto">{result.schemaMarkup}</pre>
            </div>
          )}
        </div>
      )}
    </div>
  );
};

