          {/* Content */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 leading-relaxed">
              {result.content}
            </div>
