          {/* Score + Meta */}
          <div className="flex items-center gap-6 mb-8 bg-white/[0.03] border border-white/[0.06] rounded-xl p-6">
            <ScoreRingMini score={result.aeoScore} />
            <div className="flex-1">
              <h3 className="text-lg font-bold text-white">{result.title}</h3>
              {result.metaDescription && <p className="text-sm text-gray-500 mt-1">{result.metaDescription}</p>}
            </div>
            <div className="flex gap-2">
              <button onClick={() => handleCopy(result.content)} className="p-2.5 border border-white/[0.06] bg-white/[0.03] rounded-full hover:bg-white/[0.08] transition-colors" title="Copier">
                {copied ? <Check size={16} className="text-purple-300" /> : <Copy size={16} className="text-gray-500" />}
              </button>
              <button onClick={() => handleDownload(`${brandName}-${selectedType}.md`, result.content)} className="p-2.5 border border-white/[0.06] bg-white/[0.03] rounded-full hover:bg-white/[0.08] transition-colors" title="Télécharger">
                <Download size={16} className="text-gray-500" />
              </button>
              <button onClick={handleRegenerate} className="p-2.5 border border-white/[0.06] bg-white/[0.03] rounded-full hover:bg-white/[0.08] transition-colors" title={t.common.regenerate}>
