    <div className="page-enter">
      <PageHeader title="Outils Génératifs" description="Générez du contenu optimisé pour les moteurs IA" />

      {/* Grid des Outils */}
      <div className="grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-3 gap-6 mb-12">
        {tools.map((tool) => (
            <ToolCard
