          <button
            onClick={handleScan}
            disabled={isScanning || !brandName || !industry}
            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
          </button>
        </div>
      )}

      {/* Results */}
      {step === 'results' && report && (
        <div className="space-y-6">
          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>

          {/* Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 flex flex-col items-center">
              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <SentimentGauge value={report.overallSentiment} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h4 className="text-sm font-bold text-gray-500 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
              <div className="space-y-3">
                {(['positive', 'neutral', 'negative'] as const).map(s => {
                  const count = report.sentimentBreakdown[s];
                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
                  const cfg = SENTIMENT_CONFIG[s];
                  return (
                    <div key={s}>
                      <div className="flex justify-between text-xs mb-1">
                        <span className={cfg.color}>{cfg.label}</span>
                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
                      </div>
                      <div className="h-2 bg-white/[0.03] rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Top Themes */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
            <div className="flex flex-wrap gap-2">
              {report.topThemes.map((theme, i) => {
                const cfg = SENTIMENT_CONFIG[theme.sentiment];
                return (
                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
                    {theme.theme} ({theme.count})
                  </span>
                );
              })}
            </div>
          </div>

          {/* Competitor Comparison */}
          {report.competitorComparison && report.competitorComparison.length > 0 && (
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-[var(--border-subtle)]">
                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-[var(--border-subtle)] bg-white/[0.03]">
                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
                      <td className="py-3 text-center">
                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
                        </span>
                      </td>
                    </tr>
                    {report.competitorComparison.map((c, i) => (
                      <tr key={i} className="border-b border-[var(--border-subtle)]">
                        <td className="py-3 text-gray-300">{c.name}</td>
                        <td className="py-3 text-center text-white">{c.mentions}</td>
                        <td className="py-3 text-center">
                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Alerts */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
            <div className="space-y-3">
              {report.alerts.map((alert, i) => {
                const cfg = SEVERITY_CONFIG[alert.severity];
                const SevIcon = cfg.icon;
                const isExpanded = expandedAlert === i;
                return (
                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4`}>
                    <div className="flex items-start gap-3">
                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{alert.message}</p>
                        <p className="text-xs text-gray-500 mt-1">Action : {alert.action}</p>
                      </div>
                      <button
                        onClick={() => handleGenerateActionPlan(alert, i)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
                      >
                        <Sparkles size={12} /> {t.reputation.actionPlan}
                      </button>
                    </div>
                    {isExpanded && (
                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        {isGeneratingPlan ? (
                          <div className="flex items-center gap-2 text-sm text-gray-500"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
                        ) : actionPlan ? (
                          <div>
                            <div className="flex justify-end mb-2">
                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
                              </button>
                            </div>
                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
                          </div>
                        ) : null}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Mentions */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
            <div className="space-y-3">
              {report.mentions.map((mention) => {
                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
                return (
                  <div key={mention.id} className="bg-black/20 border border-[var(--border-subtle)] rounded-2xl p-4">
                    <div className="flex items-center gap-3 mb-3">
                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-500'}`}>
                        {mention.aiEngine}
                      </span>
                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
                      </span>
                      <span className="text-xs text-[var(--text-disabled)] bg-white/[0.03] px-2 py-0.5 rounded">{mention.mentionType}</span>
                    </div>
                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recommendations */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
            <div className="space-y-2">
              {report.recommendations.map((rec, i) => (
                <div key={i} className="flex items-start gap-3 py-2">
                  <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-white/[0.06] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                  </div>
                  <p className="text-sm text-gray-300">{rec}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reputation;

import React, { useState } from 'react';
import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
import { scanReputation, generateReputationResponse } from '../services/reputation_service';
import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const AI_LOGOS: Record<string, string> = {
  ChatGPT: 'bg-purple-500/20 text-purple-300',
  Perplexity: 'bg-blue-500/20 text-blue-400',
  Claude: 'bg-orange-500/20 text-orange-400',
  Gemini: 'bg-purple-500/20 text-purple-400',
  Copilot: 'bg-cyan-500/20 text-cyan-400',
  'AI Overviews': 'bg-rose-500/20 text-rose-400',
};

const SEVERITY_CONFIG = {
  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-white/[0.06]' },
  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
};

const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const SENTIMENT_CONFIG = {
    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: 'Positif' },
    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Négatif' },
  };

  const [step, setStep] = useState<'form' | 'results'>('form');
  const [isScanning, setIsScanning] = useState(false);
  const [report, setReport] = useState<ReputationReport | null>(null);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [competitorInput, setCompetitorInput] = useState('');
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [keywordInput, setKeywordInput] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  // Action plan
  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [copied, setCopied] = useState(false);

  const addCompetitor = () => {
    if (competitorInput.trim() && competitors.length < 5) {
      setCompetitors([...competitors, competitorInput.trim()]);
      setCompetitorInput('');
    }
  };

  const addKeyword = () => {
    if (keywordInput.trim() && keywords.length < 10) {
      setKeywords([...keywords, keywordInput.trim()]);
      setKeywordInput('');
    }
  };

  const handleScan = async () => {
    if (!brandName || !industry) {
      alert('Veuillez remplir le nom de la marque et le secteur.');
      return;
    }

    const canProceed = onDeductCredits(3);
    if (!canProceed) return;

    setIsScanning(true);
    try {
      const result = await scanReputation({
        brandName,
        brandUrl: brandUrl || undefined,
        competitors: competitors.length > 0 ? competitors : undefined,
        industry,
        keywords: keywords.length > 0 ? keywords : undefined,
      }, 'fr');
      setReport(result);
      setStep('results');
    } catch (error) {
      console.error(error);
      alert('Erreur lors du scan.');
    } finally {
      setIsScanning(false);
    }
  };

  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
    setExpandedAlert(index);
    setIsGeneratingPlan(true);
    setActionPlan(null);
    try {
      const plan = await generateReputationResponse(alert, brandName, 'fr');
      setActionPlan(plan);
    } catch (e) {
      setActionPlan(locale === 'en' ? 'Error generating action plan.' : locale === 'es' ? 'Error al generar el plan de accion.' : "Erreur lors de la generation du plan d'action.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Sentiment Gauge
  const SentimentGauge = ({ value }: { value: number }) => {
    const normalized = (value + 100) / 200;
    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
    return (
      <div className="w-full">
        <div className="flex justify-between text-xs text-gray-500 mb-1">
          <span>-100</span><span>0</span><span>+100</span>
        </div>
        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
        </div>
        <div className="text-center mt-2">
          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
          <span className="text-xs text-gray-500 ml-1">sentiment</span>
        </div>
      </div>
    );
  };

  // Score Ring
  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 36;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="flex flex-col items-center">
        <div className="relative w-24 h-24">
          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-2xl font-bold text-white">{score}</span>
          </div>
        </div>
        <span className="text-xs text-gray-500 mt-2">{label}</span>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-purple-500/10 rounded-2xl">
          <Shield size={32} className="text-purple-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">{t.reputation.title}</h1>
          <p className="text-gray-500">{t.reputation.subtitle}</p>
        </div>
        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-white/[0.06]">
          {t.reputation.heuristicBadge}
        </span>
      </div>

      {/* Form */}
      {step === 'form' && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.brandName} *</label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.brandUrl} ({t.common.optional})</label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.industry} *</label>
            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
          </div>

          {/* Competitors */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.competitors}</label>
            <div className="flex gap-2">
              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder={t.reputation.addCompetitor} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addCompetitor} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {competitors.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {competitors.map((c, i) => (
                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Keywords */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.keywords}</label>
            <div className="flex gap-2">
              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addKeyword} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {keywords.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {keywords.map((k, i) => (
                  <span key={i} className="flex items-center gap-1 bg-white/[0.03] text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-4 text-sm text-gray-500">
            <div className="flex items-start gap-2">
              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
              <p>{t.reputation.heuristicBadge} — 3 GTO Gas</p>
            </div>
          </div>

          <button
            onClick={handleScan}
            disabled={isScanning || !brandName || !industry}
            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
          </button>
        </div>
      )}

      {/* Results */}
      {step === 'results' && report && (
        <div className="space-y-6">
          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>

          {/* Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 flex flex-col items-center">
              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <SentimentGauge value={report.overallSentiment} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h4 className="text-sm font-bold text-gray-500 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
              <div className="space-y-3">
                {(['positive', 'neutral', 'negative'] as const).map(s => {
                  const count = report.sentimentBreakdown[s];
                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
                  const cfg = SENTIMENT_CONFIG[s];
                  return (
                    <div key={s}>
                      <div className="flex justify-between text-xs mb-1">
                        <span className={cfg.color}>{cfg.label}</span>
                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
                      </div>
                      <div className="h-2 bg-white/[0.03] rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Top Themes */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
            <div className="flex flex-wrap gap-2">
              {report.topThemes.map((theme, i) => {
                const cfg = SENTIMENT_CONFIG[theme.sentiment];
                return (
                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
                    {theme.theme} ({theme.count})
                  </span>
                );
              })}
            </div>
          </div>

          {/* Competitor Comparison */}
          {report.competitorComparison && report.competitorComparison.length > 0 && (
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-[var(--border-subtle)]">
                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-[var(--border-subtle)] bg-white/[0.03]">
                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
                      <td className="py-3 text-center">
                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
                        </span>
                      </td>
                    </tr>
                    {report.competitorComparison.map((c, i) => (
                      <tr key={i} className="border-b border-[var(--border-subtle)]">
                        <td className="py-3 text-gray-300">{c.name}</td>
                        <td className="py-3 text-center text-white">{c.mentions}</td>
                        <td className="py-3 text-center">
                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Alerts */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
            <div className="space-y-3">
              {report.alerts.map((alert, i) => {
                const cfg = SEVERITY_CONFIG[alert.severity];
                const SevIcon = cfg.icon;
                const isExpanded = expandedAlert === i;
                return (
                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4`}>
                    <div className="flex items-start gap-3">
                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{alert.message}</p>
                        <p className="text-xs text-gray-500 mt-1">Action : {alert.action}</p>
                      </div>
                      <button
                        onClick={() => handleGenerateActionPlan(alert, i)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
                      >
                        <Sparkles size={12} /> {t.reputation.actionPlan}
                      </button>
                    </div>
                    {isExpanded && (
                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        {isGeneratingPlan ? (
                          <div className="flex items-center gap-2 text-sm text-gray-500"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
                        ) : actionPlan ? (
                          <div>
                            <div className="flex justify-end mb-2">
                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
                              </button>
                            </div>
                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
                          </div>
                        ) : null}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Mentions */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
            <div className="space-y-3">
              {report.mentions.map((mention) => {
                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
                return (
                  <div key={mention.id} className="bg-black/20 border border-[var(--border-subtle)] rounded-2xl p-4">
                    <div className="flex items-center gap-3 mb-3">
                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-500'}`}>
                        {mention.aiEngine}
                      </span>
                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
                      </span>
                      <span className="text-xs text-[var(--text-disabled)] bg-white/[0.03] px-2 py-0.5 rounded">{mention.mentionType}</span>
                    </div>
                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recommendations */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
            <div className="space-y-2">
              {report.recommendations.map((rec, i) => (
                <div key={i} className="flex items-start gap-3 py-2">
                  <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-white/[0.06] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                  </div>
                  <p className="text-sm text-gray-300">{rec}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reputation;

import React, { useState } from 'react';
import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
import { scanReputation, generateReputationResponse } from '../services/reputation_service';
import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const AI_LOGOS: Record<string, string> = {
  ChatGPT: 'bg-purple-500/20 text-purple-300',
  Perplexity: 'bg-blue-500/20 text-blue-400',
  Claude: 'bg-orange-500/20 text-orange-400',
  Gemini: 'bg-purple-500/20 text-purple-400',
  Copilot: 'bg-cyan-500/20 text-cyan-400',
  'AI Overviews': 'bg-rose-500/20 text-rose-400',
};

const SEVERITY_CONFIG = {
  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-white/[0.06]' },
  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
};

const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const SENTIMENT_CONFIG = {
    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: 'Positif' },
    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Négatif' },
  };

  const [step, setStep] = useState<'form' | 'results'>('form');
  const [isScanning, setIsScanning] = useState(false);
  const [report, setReport] = useState<ReputationReport | null>(null);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [competitorInput, setCompetitorInput] = useState('');
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [keywordInput, setKeywordInput] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  // Action plan
  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [copied, setCopied] = useState(false);

  const addCompetitor = () => {
    if (competitorInput.trim() && competitors.length < 5) {
      setCompetitors([...competitors, competitorInput.trim()]);
      setCompetitorInput('');
    }
  };

  const addKeyword = () => {
    if (keywordInput.trim() && keywords.length < 10) {
      setKeywords([...keywords, keywordInput.trim()]);
      setKeywordInput('');
    }
  };

  const handleScan = async () => {
    if (!brandName || !industry) {
      alert('Veuillez remplir le nom de la marque et le secteur.');
      return;
    }

    const canProceed = onDeductCredits(3);
    if (!canProceed) return;

    setIsScanning(true);
    try {
      const result = await scanReputation({
        brandName,
        brandUrl: brandUrl || undefined,
        competitors: competitors.length > 0 ? competitors : undefined,
        industry,
        keywords: keywords.length > 0 ? keywords : undefined,
      }, 'fr');
      setReport(result);
      setStep('results');
    } catch (error) {
      console.error(error);
      alert('Erreur lors du scan.');
    } finally {
      setIsScanning(false);
    }
  };

  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
    setExpandedAlert(index);
    setIsGeneratingPlan(true);
    setActionPlan(null);
    try {
      const plan = await generateReputationResponse(alert, brandName, 'fr');
      setActionPlan(plan);
    } catch (e) {
      setActionPlan("Erreur lors de la génération du plan d'action.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Sentiment Gauge
  const SentimentGauge = ({ value }: { value: number }) => {
    const normalized = (value + 100) / 200;
    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
    return (
      <div className="w-full">
        <div className="flex justify-between text-xs text-gray-500 mb-1">
          <span>-100</span><span>0</span><span>+100</span>
        </div>
        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
        </div>
        <div className="text-center mt-2">
          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
          <span className="text-xs text-gray-500 ml-1">sentiment</span>
        </div>
      </div>
    );
  };

  // Score Ring
  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 36;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="flex flex-col items-center">
        <div className="relative w-24 h-24">
          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-2xl font-bold text-white">{score}</span>
          </div>
        </div>
        <span className="text-xs text-gray-500 mt-2">{label}</span>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-purple-500/10 rounded-2xl">
          <Shield size={32} className="text-purple-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">{t.reputation.title}</h1>
          <p className="text-gray-500">{t.reputation.subtitle}</p>
        </div>
        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-white/[0.06]">
          {t.reputation.heuristicBadge}
        </span>
      </div>

      {/* Form */}
      {step === 'form' && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.brandName} *</label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.brandUrl} ({t.common.optional})</label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.industry} *</label>
            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
          </div>

          {/* Competitors */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.competitors}</label>
            <div className="flex gap-2">
              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder={t.reputation.addCompetitor} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addCompetitor} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {competitors.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {competitors.map((c, i) => (
                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Keywords */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.keywords}</label>
            <div className="flex gap-2">
              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addKeyword} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {keywords.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {keywords.map((k, i) => (
                  <span key={i} className="flex items-center gap-1 bg-white/[0.03] text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-4 text-sm text-gray-500">
            <div className="flex items-start gap-2">
              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
              <p>{t.reputation.heuristicBadge} — 3 GTO Gas</p>
            </div>
          </div>

          <button
            onClick={handleScan}
            disabled={isScanning || !brandName || !industry}
            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
          </button>
        </div>
      )}

      {/* Results */}
      {step === 'results' && report && (
        <div className="space-y-6">
          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>

          {/* Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 flex flex-col items-center">
              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <SentimentGauge value={report.overallSentiment} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h4 className="text-sm font-bold text-gray-500 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
              <div className="space-y-3">
                {(['positive', 'neutral', 'negative'] as const).map(s => {
                  const count = report.sentimentBreakdown[s];
                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
                  const cfg = SENTIMENT_CONFIG[s];
                  return (
                    <div key={s}>
                      <div className="flex justify-between text-xs mb-1">
                        <span className={cfg.color}>{cfg.label}</span>
                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
                      </div>
                      <div className="h-2 bg-white/[0.03] rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Top Themes */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
            <div className="flex flex-wrap gap-2">
              {report.topThemes.map((theme, i) => {
                const cfg = SENTIMENT_CONFIG[theme.sentiment];
                return (
                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
                    {theme.theme} ({theme.count})
                  </span>
                );
              })}
            </div>
          </div>

          {/* Competitor Comparison */}
          {report.competitorComparison && report.competitorComparison.length > 0 && (
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-[var(--border-subtle)]">
                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-[var(--border-subtle)] bg-white/[0.03]">
                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
                      <td className="py-3 text-center">
                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
                        </span>
                      </td>
                    </tr>
                    {report.competitorComparison.map((c, i) => (
                      <tr key={i} className="border-b border-[var(--border-subtle)]">
                        <td className="py-3 text-gray-300">{c.name}</td>
                        <td className="py-3 text-center text-white">{c.mentions}</td>
                        <td className="py-3 text-center">
                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Alerts */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
            <div className="space-y-3">
              {report.alerts.map((alert, i) => {
                const cfg = SEVERITY_CONFIG[alert.severity];
                const SevIcon = cfg.icon;
                const isExpanded = expandedAlert === i;
                return (
                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4`}>
                    <div className="flex items-start gap-3">
                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{alert.message}</p>
                        <p className="text-xs text-gray-500 mt-1">Action : {alert.action}</p>
                      </div>
                      <button
                        onClick={() => handleGenerateActionPlan(alert, i)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
                      >
                        <Sparkles size={12} /> {t.reputation.actionPlan}
                      </button>
                    </div>
                    {isExpanded && (
                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        {isGeneratingPlan ? (
                          <div className="flex items-center gap-2 text-sm text-gray-500"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
                        ) : actionPlan ? (
                          <div>
                            <div className="flex justify-end mb-2">
                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
                              </button>
                            </div>
                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
                          </div>
                        ) : null}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Mentions */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
            <div className="space-y-3">
              {report.mentions.map((mention) => {
                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
                return (
                  <div key={mention.id} className="bg-black/20 border border-[var(--border-subtle)] rounded-2xl p-4">
                    <div className="flex items-center gap-3 mb-3">
                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-500'}`}>
                        {mention.aiEngine}
                      </span>
                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
                      </span>
                      <span className="text-xs text-[var(--text-disabled)] bg-white/[0.03] px-2 py-0.5 rounded">{mention.mentionType}</span>
                    </div>
                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recommendations */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
            <div className="space-y-2">
              {report.recommendations.map((rec, i) => (
                <div key={i} className="flex items-start gap-3 py-2">
                  <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-white/[0.06] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                  </div>
                  <p className="text-sm text-gray-300">{rec}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reputation;

import React, { useState } from 'react';
import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
import { scanReputation, generateReputationResponse } from '../services/reputation_service';
import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const AI_LOGOS: Record<string, string> = {
  ChatGPT: 'bg-purple-500/20 text-purple-300',
  Perplexity: 'bg-blue-500/20 text-blue-400',
  Claude: 'bg-orange-500/20 text-orange-400',
  Gemini: 'bg-purple-500/20 text-purple-400',
  Copilot: 'bg-cyan-500/20 text-cyan-400',
  'AI Overviews': 'bg-rose-500/20 text-rose-400',
};

const SEVERITY_CONFIG = {
  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-white/[0.06]' },
  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
};

const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const SENTIMENT_CONFIG = {
    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: 'Positif' },
    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Négatif' },
  };

  const [step, setStep] = useState<'form' | 'results'>('form');
  const [isScanning, setIsScanning] = useState(false);
  const [report, setReport] = useState<ReputationReport | null>(null);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [competitorInput, setCompetitorInput] = useState('');
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [keywordInput, setKeywordInput] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  // Action plan
  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [copied, setCopied] = useState(false);

  const addCompetitor = () => {
    if (competitorInput.trim() && competitors.length < 5) {
      setCompetitors([...competitors, competitorInput.trim()]);
      setCompetitorInput('');
    }
  };

  const addKeyword = () => {
    if (keywordInput.trim() && keywords.length < 10) {
      setKeywords([...keywords, keywordInput.trim()]);
      setKeywordInput('');
    }
  };

  const handleScan = async () => {
    if (!brandName || !industry) {
      alert('Veuillez remplir le nom de la marque et le secteur.');
      return;
    }

    const canProceed = onDeductCredits(3);
    if (!canProceed) return;

    setIsScanning(true);
    try {
      const result = await scanReputation({
        brandName,
        brandUrl: brandUrl || undefined,
        competitors: competitors.length > 0 ? competitors : undefined,
        industry,
        keywords: keywords.length > 0 ? keywords : undefined,
      }, 'fr');
      setReport(result);
      setStep('results');
    } catch (error) {
      console.error(error);
      alert('Erreur lors du scan.');
    } finally {
      setIsScanning(false);
    }
  };

  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
    setExpandedAlert(index);
    setIsGeneratingPlan(true);
    setActionPlan(null);
    try {
      const plan = await generateReputationResponse(alert, brandName, 'fr');
      setActionPlan(plan);
    } catch (e) {
      setActionPlan("Erreur lors de la génération du plan d'action.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Sentiment Gauge
  const SentimentGauge = ({ value }: { value: number }) => {
    const normalized = (value + 100) / 200;
    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
    return (
      <div className="w-full">
        <div className="flex justify-between text-xs text-gray-500 mb-1">
          <span>-100</span><span>0</span><span>+100</span>
        </div>
        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
        </div>
        <div className="text-center mt-2">
          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
          <span className="text-xs text-gray-500 ml-1">sentiment</span>
        </div>
      </div>
    );
  };

  // Score Ring
  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 36;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="flex flex-col items-center">
        <div className="relative w-24 h-24">
          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-2xl font-bold text-white">{score}</span>
          </div>
        </div>
        <span className="text-xs text-gray-500 mt-2">{label}</span>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-purple-500/10 rounded-2xl">
          <Shield size={32} className="text-purple-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">Réputation IA</h1>
          <p className="text-gray-500">Indice de visibilité & sentiment dans les réponses IA</p>
        </div>
        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-white/[0.06]">
          {t.reputation.heuristicBadge}
        </span>
      </div>

      {/* Form */}
      {step === 'form' && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.brandName} *</label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.brandUrl} ({t.common.optional})</label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.industry} *</label>
            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
          </div>

          {/* Competitors */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.competitors}</label>
            <div className="flex gap-2">
              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder={t.reputation.addCompetitor} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addCompetitor} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {competitors.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {competitors.map((c, i) => (
                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Keywords */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.keywords}</label>
            <div className="flex gap-2">
              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addKeyword} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {keywords.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {keywords.map((k, i) => (
                  <span key={i} className="flex items-center gap-1 bg-white/[0.03] text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-4 text-sm text-gray-500">
            <div className="flex items-start gap-2">
              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
              <p>{t.reputation.heuristicBadge} — 3 GTO Gas</p>
            </div>
          </div>

          <button
            onClick={handleScan}
            disabled={isScanning || !brandName || !industry}
            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
          </button>
        </div>
      )}

      {/* Results */}
      {step === 'results' && report && (
        <div className="space-y-6">
          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>

          {/* Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 flex flex-col items-center">
              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <SentimentGauge value={report.overallSentiment} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h4 className="text-sm font-bold text-gray-500 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
              <div className="space-y-3">
                {(['positive', 'neutral', 'negative'] as const).map(s => {
                  const count = report.sentimentBreakdown[s];
                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
                  const cfg = SENTIMENT_CONFIG[s];
                  return (
                    <div key={s}>
                      <div className="flex justify-between text-xs mb-1">
                        <span className={cfg.color}>{cfg.label}</span>
                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
                      </div>
                      <div className="h-2 bg-white/[0.03] rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Top Themes */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
            <div className="flex flex-wrap gap-2">
              {report.topThemes.map((theme, i) => {
                const cfg = SENTIMENT_CONFIG[theme.sentiment];
                return (
                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
                    {theme.theme} ({theme.count})
                  </span>
                );
              })}
            </div>
          </div>

          {/* Competitor Comparison */}
          {report.competitorComparison && report.competitorComparison.length > 0 && (
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-[var(--border-subtle)]">
                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-[var(--border-subtle)] bg-white/[0.03]">
                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
                      <td className="py-3 text-center">
                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
                        </span>
                      </td>
                    </tr>
                    {report.competitorComparison.map((c, i) => (
                      <tr key={i} className="border-b border-[var(--border-subtle)]">
                        <td className="py-3 text-gray-300">{c.name}</td>
                        <td className="py-3 text-center text-white">{c.mentions}</td>
                        <td className="py-3 text-center">
                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Alerts */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
            <div className="space-y-3">
              {report.alerts.map((alert, i) => {
                const cfg = SEVERITY_CONFIG[alert.severity];
                const SevIcon = cfg.icon;
                const isExpanded = expandedAlert === i;
                return (
                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4`}>
                    <div className="flex items-start gap-3">
                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{alert.message}</p>
                        <p className="text-xs text-gray-500 mt-1">Action : {alert.action}</p>
                      </div>
                      <button
                        onClick={() => handleGenerateActionPlan(alert, i)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
                      >
                        <Sparkles size={12} /> {t.reputation.actionPlan}
                      </button>
                    </div>
                    {isExpanded && (
                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        {isGeneratingPlan ? (
                          <div className="flex items-center gap-2 text-sm text-gray-500"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
                        ) : actionPlan ? (
                          <div>
                            <div className="flex justify-end mb-2">
                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
                              </button>
                            </div>
                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
                          </div>
                        ) : null}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Mentions */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
            <div className="space-y-3">
              {report.mentions.map((mention) => {
                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
                return (
                  <div key={mention.id} className="bg-black/20 border border-[var(--border-subtle)] rounded-2xl p-4">
                    <div className="flex items-center gap-3 mb-3">
                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-500'}`}>
                        {mention.aiEngine}
                      </span>
                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
                      </span>
                      <span className="text-xs text-[var(--text-disabled)] bg-white/[0.03] px-2 py-0.5 rounded">{mention.mentionType}</span>
                    </div>
                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recommendations */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
            <div className="space-y-2">
              {report.recommendations.map((rec, i) => (
                <div key={i} className="flex items-start gap-3 py-2">
                  <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-white/[0.06] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                  </div>
                  <p className="text-sm text-gray-300">{rec}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reputation;

import React, { useState } from 'react';
import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
import { scanReputation, generateReputationResponse } from '../services/reputation_service';
import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const AI_LOGOS: Record<string, string> = {
  ChatGPT: 'bg-purple-500/20 text-purple-300',
  Perplexity: 'bg-blue-500/20 text-blue-400',
  Claude: 'bg-orange-500/20 text-orange-400',
  Gemini: 'bg-purple-500/20 text-purple-400',
  Copilot: 'bg-cyan-500/20 text-cyan-400',
  'AI Overviews': 'bg-rose-500/20 text-rose-400',
};

const SEVERITY_CONFIG = {
  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-white/[0.06]' },
  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
};

const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const SENTIMENT_CONFIG = {
    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: 'Positif' },
    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Négatif' },
  };

  const [step, setStep] = useState<'form' | 'results'>('form');
  const [isScanning, setIsScanning] = useState(false);
  const [report, setReport] = useState<ReputationReport | null>(null);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [competitorInput, setCompetitorInput] = useState('');
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [keywordInput, setKeywordInput] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  // Action plan
  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [copied, setCopied] = useState(false);

  const addCompetitor = () => {
    if (competitorInput.trim() && competitors.length < 5) {
      setCompetitors([...competitors, competitorInput.trim()]);
      setCompetitorInput('');
    }
  };

  const addKeyword = () => {
    if (keywordInput.trim() && keywords.length < 10) {
      setKeywords([...keywords, keywordInput.trim()]);
      setKeywordInput('');
    }
  };

  const handleScan = async () => {
    if (!brandName || !industry) {
      alert('Veuillez remplir le nom de la marque et le secteur.');
      return;
    }

    const canProceed = onDeductCredits(3);
    if (!canProceed) return;

    setIsScanning(true);
    try {
      const result = await scanReputation({
        brandName,
        brandUrl: brandUrl || undefined,
        competitors: competitors.length > 0 ? competitors : undefined,
        industry,
        keywords: keywords.length > 0 ? keywords : undefined,
      }, 'fr');
      setReport(result);
      setStep('results');
    } catch (error) {
      console.error(error);
      alert('Erreur lors du scan.');
    } finally {
      setIsScanning(false);
    }
  };

  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
    setExpandedAlert(index);
    setIsGeneratingPlan(true);
    setActionPlan(null);
    try {
      const plan = await generateReputationResponse(alert, brandName, 'fr');
      setActionPlan(plan);
    } catch (e) {
      setActionPlan("Erreur lors de la génération du plan d'action.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Sentiment Gauge
  const SentimentGauge = ({ value }: { value: number }) => {
    const normalized = (value + 100) / 200;
    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
    return (
      <div className="w-full">
        <div className="flex justify-between text-xs text-gray-500 mb-1">
          <span>-100</span><span>0</span><span>+100</span>
        </div>
        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
        </div>
        <div className="text-center mt-2">
          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
          <span className="text-xs text-gray-500 ml-1">sentiment</span>
        </div>
      </div>
    );
  };

  // Score Ring
  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 36;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="flex flex-col items-center">
        <div className="relative w-24 h-24">
          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-2xl font-bold text-white">{score}</span>
          </div>
        </div>
        <span className="text-xs text-gray-500 mt-2">{label}</span>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-purple-500/10 rounded-2xl">
          <Shield size={32} className="text-purple-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">Réputation IA</h1>
          <p className="text-gray-500">Indice de visibilité & sentiment dans les réponses IA</p>
        </div>
        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-white/[0.06]">
          INDICE HEURISTIQUE
        </span>
      </div>

      {/* Form */}
      {step === 'form' && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.brandName} *</label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.brandUrl} ({t.common.optional})</label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.industry} *</label>
            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
          </div>

          {/* Competitors */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.competitors}</label>
            <div className="flex gap-2">
              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder={t.reputation.addCompetitor} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addCompetitor} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {competitors.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {competitors.map((c, i) => (
                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Keywords */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.keywords}</label>
            <div className="flex gap-2">
              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addKeyword} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {keywords.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {keywords.map((k, i) => (
                  <span key={i} className="flex items-center gap-1 bg-white/[0.03] text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-4 text-sm text-gray-500">
            <div className="flex items-start gap-2">
              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
              <p>{t.reputation.heuristicBadge} — 3 GTO Gas</p>
            </div>
          </div>

          <button
            onClick={handleScan}
            disabled={isScanning || !brandName || !industry}
            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
          </button>
        </div>
      )}

      {/* Results */}
      {step === 'results' && report && (
        <div className="space-y-6">
          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>

          {/* Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 flex flex-col items-center">
              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <SentimentGauge value={report.overallSentiment} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h4 className="text-sm font-bold text-gray-500 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
              <div className="space-y-3">
                {(['positive', 'neutral', 'negative'] as const).map(s => {
                  const count = report.sentimentBreakdown[s];
                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
                  const cfg = SENTIMENT_CONFIG[s];
                  return (
                    <div key={s}>
                      <div className="flex justify-between text-xs mb-1">
                        <span className={cfg.color}>{cfg.label}</span>
                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
                      </div>
                      <div className="h-2 bg-white/[0.03] rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Top Themes */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
            <div className="flex flex-wrap gap-2">
              {report.topThemes.map((theme, i) => {
                const cfg = SENTIMENT_CONFIG[theme.sentiment];
                return (
                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
                    {theme.theme} ({theme.count})
                  </span>
                );
              })}
            </div>
          </div>

          {/* Competitor Comparison */}
          {report.competitorComparison && report.competitorComparison.length > 0 && (
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-[var(--border-subtle)]">
                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-[var(--border-subtle)] bg-white/[0.03]">
                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
                      <td className="py-3 text-center">
                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
                        </span>
                      </td>
                    </tr>
                    {report.competitorComparison.map((c, i) => (
                      <tr key={i} className="border-b border-[var(--border-subtle)]">
                        <td className="py-3 text-gray-300">{c.name}</td>
                        <td className="py-3 text-center text-white">{c.mentions}</td>
                        <td className="py-3 text-center">
                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Alerts */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
            <div className="space-y-3">
              {report.alerts.map((alert, i) => {
                const cfg = SEVERITY_CONFIG[alert.severity];
                const SevIcon = cfg.icon;
                const isExpanded = expandedAlert === i;
                return (
                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4`}>
                    <div className="flex items-start gap-3">
                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{alert.message}</p>
                        <p className="text-xs text-gray-500 mt-1">Action : {alert.action}</p>
                      </div>
                      <button
                        onClick={() => handleGenerateActionPlan(alert, i)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
                      >
                        <Sparkles size={12} /> {t.reputation.actionPlan}
                      </button>
                    </div>
                    {isExpanded && (
                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        {isGeneratingPlan ? (
                          <div className="flex items-center gap-2 text-sm text-gray-500"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
                        ) : actionPlan ? (
                          <div>
                            <div className="flex justify-end mb-2">
                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
                              </button>
                            </div>
                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
                          </div>
                        ) : null}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Mentions */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
            <div className="space-y-3">
              {report.mentions.map((mention) => {
                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
                return (
                  <div key={mention.id} className="bg-black/20 border border-[var(--border-subtle)] rounded-2xl p-4">
                    <div className="flex items-center gap-3 mb-3">
                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-500'}`}>
                        {mention.aiEngine}
                      </span>
                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
                      </span>
                      <span className="text-xs text-[var(--text-disabled)] bg-white/[0.03] px-2 py-0.5 rounded">{mention.mentionType}</span>
                    </div>
                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recommendations */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
            <div className="space-y-2">
              {report.recommendations.map((rec, i) => (
                <div key={i} className="flex items-start gap-3 py-2">
                  <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-white/[0.06] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                  </div>
                  <p className="text-sm text-gray-300">{rec}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reputation;

import React, { useState } from 'react';
import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
import { scanReputation, generateReputationResponse } from '../services/reputation_service';
import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const AI_LOGOS: Record<string, string> = {
  ChatGPT: 'bg-purple-500/20 text-purple-300',
  Perplexity: 'bg-blue-500/20 text-blue-400',
  Claude: 'bg-orange-500/20 text-orange-400',
  Gemini: 'bg-purple-500/20 text-purple-400',
  Copilot: 'bg-cyan-500/20 text-cyan-400',
  'AI Overviews': 'bg-rose-500/20 text-rose-400',
};

const SEVERITY_CONFIG = {
  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-white/[0.06]' },
  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
};

const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const SENTIMENT_CONFIG = {
    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: 'Positif' },
    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Négatif' },
  };

  const [step, setStep] = useState<'form' | 'results'>('form');
  const [isScanning, setIsScanning] = useState(false);
  const [report, setReport] = useState<ReputationReport | null>(null);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [competitorInput, setCompetitorInput] = useState('');
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [keywordInput, setKeywordInput] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  // Action plan
  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [copied, setCopied] = useState(false);

  const addCompetitor = () => {
    if (competitorInput.trim() && competitors.length < 5) {
      setCompetitors([...competitors, competitorInput.trim()]);
      setCompetitorInput('');
    }
  };

  const addKeyword = () => {
    if (keywordInput.trim() && keywords.length < 10) {
      setKeywords([...keywords, keywordInput.trim()]);
      setKeywordInput('');
    }
  };

  const handleScan = async () => {
    if (!brandName || !industry) {
      alert('Veuillez remplir le nom de la marque et le secteur.');
      return;
    }

    const canProceed = onDeductCredits(3);
    if (!canProceed) return;

    setIsScanning(true);
    try {
      const result = await scanReputation({
        brandName,
        brandUrl: brandUrl || undefined,
        competitors: competitors.length > 0 ? competitors : undefined,
        industry,
        keywords: keywords.length > 0 ? keywords : undefined,
      }, 'fr');
      setReport(result);
      setStep('results');
    } catch (error) {
      console.error(error);
      alert('Erreur lors du scan.');
    } finally {
      setIsScanning(false);
    }
  };

  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
    setExpandedAlert(index);
    setIsGeneratingPlan(true);
    setActionPlan(null);
    try {
      const plan = await generateReputationResponse(alert, brandName, 'fr');
      setActionPlan(plan);
    } catch (e) {
      setActionPlan("Erreur lors de la génération du plan d'action.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Sentiment Gauge
  const SentimentGauge = ({ value }: { value: number }) => {
    const normalized = (value + 100) / 200;
    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
    return (
      <div className="w-full">
        <div className="flex justify-between text-xs text-gray-500 mb-1">
          <span>-100</span><span>0</span><span>+100</span>
        </div>
        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
        </div>
        <div className="text-center mt-2">
          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
          <span className="text-xs text-gray-500 ml-1">sentiment</span>
        </div>
      </div>
    );
  };

  // Score Ring
  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 36;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="flex flex-col items-center">
        <div className="relative w-24 h-24">
          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-2xl font-bold text-white">{score}</span>
          </div>
        </div>
        <span className="text-xs text-gray-500 mt-2">{label}</span>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-purple-500/10 rounded-2xl">
          <Shield size={32} className="text-purple-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">Réputation IA</h1>
          <p className="text-gray-500">Indice de visibilité & sentiment dans les réponses IA</p>
        </div>
        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-white/[0.06]">
          INDICE HEURISTIQUE
        </span>
      </div>

      {/* Form */}
      {step === 'form' && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">Nom de la marque *</label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.brandUrl} ({t.common.optional})</label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.industry} *</label>
            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
          </div>

          {/* Competitors */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.competitors}</label>
            <div className="flex gap-2">
              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder={t.reputation.addCompetitor} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addCompetitor} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {competitors.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {competitors.map((c, i) => (
                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Keywords */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.keywords}</label>
            <div className="flex gap-2">
              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addKeyword} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {keywords.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {keywords.map((k, i) => (
                  <span key={i} className="flex items-center gap-1 bg-white/[0.03] text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-4 text-sm text-gray-500">
            <div className="flex items-start gap-2">
              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
              <p>{t.reputation.heuristicBadge} — 3 GTO Gas</p>
            </div>
          </div>

          <button
            onClick={handleScan}
            disabled={isScanning || !brandName || !industry}
            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
          </button>
        </div>
      )}

      {/* Results */}
      {step === 'results' && report && (
        <div className="space-y-6">
          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>

          {/* Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 flex flex-col items-center">
              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <SentimentGauge value={report.overallSentiment} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h4 className="text-sm font-bold text-gray-500 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
              <div className="space-y-3">
                {(['positive', 'neutral', 'negative'] as const).map(s => {
                  const count = report.sentimentBreakdown[s];
                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
                  const cfg = SENTIMENT_CONFIG[s];
                  return (
                    <div key={s}>
                      <div className="flex justify-between text-xs mb-1">
                        <span className={cfg.color}>{cfg.label}</span>
                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
                      </div>
                      <div className="h-2 bg-white/[0.03] rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Top Themes */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
            <div className="flex flex-wrap gap-2">
              {report.topThemes.map((theme, i) => {
                const cfg = SENTIMENT_CONFIG[theme.sentiment];
                return (
                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
                    {theme.theme} ({theme.count})
                  </span>
                );
              })}
            </div>
          </div>

          {/* Competitor Comparison */}
          {report.competitorComparison && report.competitorComparison.length > 0 && (
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-[var(--border-subtle)]">
                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-[var(--border-subtle)] bg-white/[0.03]">
                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
                      <td className="py-3 text-center">
                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
                        </span>
                      </td>
                    </tr>
                    {report.competitorComparison.map((c, i) => (
                      <tr key={i} className="border-b border-[var(--border-subtle)]">
                        <td className="py-3 text-gray-300">{c.name}</td>
                        <td className="py-3 text-center text-white">{c.mentions}</td>
                        <td className="py-3 text-center">
                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Alerts */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
            <div className="space-y-3">
              {report.alerts.map((alert, i) => {
                const cfg = SEVERITY_CONFIG[alert.severity];
                const SevIcon = cfg.icon;
                const isExpanded = expandedAlert === i;
                return (
                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4`}>
                    <div className="flex items-start gap-3">
                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{alert.message}</p>
                        <p className="text-xs text-gray-500 mt-1">Action : {alert.action}</p>
                      </div>
                      <button
                        onClick={() => handleGenerateActionPlan(alert, i)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
                      >
                        <Sparkles size={12} /> {t.reputation.actionPlan}
                      </button>
                    </div>
                    {isExpanded && (
                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        {isGeneratingPlan ? (
                          <div className="flex items-center gap-2 text-sm text-gray-500"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
                        ) : actionPlan ? (
                          <div>
                            <div className="flex justify-end mb-2">
                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
                              </button>
                            </div>
                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
                          </div>
                        ) : null}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Mentions */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
            <div className="space-y-3">
              {report.mentions.map((mention) => {
                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
                return (
                  <div key={mention.id} className="bg-black/20 border border-[var(--border-subtle)] rounded-2xl p-4">
                    <div className="flex items-center gap-3 mb-3">
                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-500'}`}>
                        {mention.aiEngine}
                      </span>
                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
                      </span>
                      <span className="text-xs text-[var(--text-disabled)] bg-white/[0.03] px-2 py-0.5 rounded">{mention.mentionType}</span>
                    </div>
                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recommendations */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
            <div className="space-y-2">
              {report.recommendations.map((rec, i) => (
                <div key={i} className="flex items-start gap-3 py-2">
                  <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-white/[0.06] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                  </div>
                  <p className="text-sm text-gray-300">{rec}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reputation;

import React, { useState } from 'react';
import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
import { scanReputation, generateReputationResponse } from '../services/reputation_service';
import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const AI_LOGOS: Record<string, string> = {
  ChatGPT: 'bg-purple-500/20 text-purple-300',
  Perplexity: 'bg-blue-500/20 text-blue-400',
  Claude: 'bg-orange-500/20 text-orange-400',
  Gemini: 'bg-purple-500/20 text-purple-400',
  Copilot: 'bg-cyan-500/20 text-cyan-400',
  'AI Overviews': 'bg-rose-500/20 text-rose-400',
};

const SEVERITY_CONFIG = {
  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-white/[0.06]' },
  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
};

const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const SENTIMENT_CONFIG = {
    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: 'Positif' },
    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Négatif' },
  };

  const [step, setStep] = useState<'form' | 'results'>('form');
  const [isScanning, setIsScanning] = useState(false);
  const [report, setReport] = useState<ReputationReport | null>(null);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [competitorInput, setCompetitorInput] = useState('');
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [keywordInput, setKeywordInput] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  // Action plan
  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [copied, setCopied] = useState(false);

  const addCompetitor = () => {
    if (competitorInput.trim() && competitors.length < 5) {
      setCompetitors([...competitors, competitorInput.trim()]);
      setCompetitorInput('');
    }
  };

  const addKeyword = () => {
    if (keywordInput.trim() && keywords.length < 10) {
      setKeywords([...keywords, keywordInput.trim()]);
      setKeywordInput('');
    }
  };

  const handleScan = async () => {
    if (!brandName || !industry) {
      alert('Veuillez remplir le nom de la marque et le secteur.');
      return;
    }

    const canProceed = onDeductCredits(3);
    if (!canProceed) return;

    setIsScanning(true);
    try {
      const result = await scanReputation({
        brandName,
        brandUrl: brandUrl || undefined,
        competitors: competitors.length > 0 ? competitors : undefined,
        industry,
        keywords: keywords.length > 0 ? keywords : undefined,
      }, 'fr');
      setReport(result);
      setStep('results');
    } catch (error) {
      console.error(error);
      alert('Erreur lors du scan.');
    } finally {
      setIsScanning(false);
    }
  };

  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
    setExpandedAlert(index);
    setIsGeneratingPlan(true);
    setActionPlan(null);
    try {
      const plan = await generateReputationResponse(alert, brandName, 'fr');
      setActionPlan(plan);
    } catch (e) {
      setActionPlan("Erreur lors de la génération du plan d'action.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Sentiment Gauge
  const SentimentGauge = ({ value }: { value: number }) => {
    const normalized = (value + 100) / 200;
    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
    return (
      <div className="w-full">
        <div className="flex justify-between text-xs text-gray-500 mb-1">
          <span>-100</span><span>0</span><span>+100</span>
        </div>
        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
        </div>
        <div className="text-center mt-2">
          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
          <span className="text-xs text-gray-500 ml-1">sentiment</span>
        </div>
      </div>
    );
  };

  // Score Ring
  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 36;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="flex flex-col items-center">
        <div className="relative w-24 h-24">
          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-2xl font-bold text-white">{score}</span>
          </div>
        </div>
        <span className="text-xs text-gray-500 mt-2">{label}</span>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-purple-500/10 rounded-2xl">
          <Shield size={32} className="text-purple-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">Réputation IA</h1>
          <p className="text-gray-500">Indice de visibilité & sentiment dans les réponses IA</p>
        </div>
        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-white/[0.06]">
          INDICE HEURISTIQUE
        </span>
      </div>

      {/* Form */}
      {step === 'form' && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">Nom de la marque *</label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">URL du site (optionnel)</label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.industry} *</label>
            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
          </div>

          {/* Competitors */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.competitors}</label>
            <div className="flex gap-2">
              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder={t.reputation.addCompetitor} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addCompetitor} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {competitors.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {competitors.map((c, i) => (
                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Keywords */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.keywords}</label>
            <div className="flex gap-2">
              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addKeyword} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {keywords.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {keywords.map((k, i) => (
                  <span key={i} className="flex items-center gap-1 bg-white/[0.03] text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-4 text-sm text-gray-500">
            <div className="flex items-start gap-2">
              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
              <p>{t.reputation.heuristicBadge} — 3 GTO Gas</p>
            </div>
          </div>

          <button
            onClick={handleScan}
            disabled={isScanning || !brandName || !industry}
            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
          </button>
        </div>
      )}

      {/* Results */}
      {step === 'results' && report && (
        <div className="space-y-6">
          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>

          {/* Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 flex flex-col items-center">
              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <SentimentGauge value={report.overallSentiment} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h4 className="text-sm font-bold text-gray-500 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
              <div className="space-y-3">
                {(['positive', 'neutral', 'negative'] as const).map(s => {
                  const count = report.sentimentBreakdown[s];
                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
                  const cfg = SENTIMENT_CONFIG[s];
                  return (
                    <div key={s}>
                      <div className="flex justify-between text-xs mb-1">
                        <span className={cfg.color}>{cfg.label}</span>
                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
                      </div>
                      <div className="h-2 bg-white/[0.03] rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Top Themes */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
            <div className="flex flex-wrap gap-2">
              {report.topThemes.map((theme, i) => {
                const cfg = SENTIMENT_CONFIG[theme.sentiment];
                return (
                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
                    {theme.theme} ({theme.count})
                  </span>
                );
              })}
            </div>
          </div>

          {/* Competitor Comparison */}
          {report.competitorComparison && report.competitorComparison.length > 0 && (
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-[var(--border-subtle)]">
                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-[var(--border-subtle)] bg-white/[0.03]">
                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
                      <td className="py-3 text-center">
                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
                        </span>
                      </td>
                    </tr>
                    {report.competitorComparison.map((c, i) => (
                      <tr key={i} className="border-b border-[var(--border-subtle)]">
                        <td className="py-3 text-gray-300">{c.name}</td>
                        <td className="py-3 text-center text-white">{c.mentions}</td>
                        <td className="py-3 text-center">
                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Alerts */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
            <div className="space-y-3">
              {report.alerts.map((alert, i) => {
                const cfg = SEVERITY_CONFIG[alert.severity];
                const SevIcon = cfg.icon;
                const isExpanded = expandedAlert === i;
                return (
                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4`}>
                    <div className="flex items-start gap-3">
                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{alert.message}</p>
                        <p className="text-xs text-gray-500 mt-1">Action : {alert.action}</p>
                      </div>
                      <button
                        onClick={() => handleGenerateActionPlan(alert, i)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
                      >
                        <Sparkles size={12} /> {t.reputation.actionPlan}
                      </button>
                    </div>
                    {isExpanded && (
                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        {isGeneratingPlan ? (
                          <div className="flex items-center gap-2 text-sm text-gray-500"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
                        ) : actionPlan ? (
                          <div>
                            <div className="flex justify-end mb-2">
                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
                              </button>
                            </div>
                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
                          </div>
                        ) : null}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Mentions */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
            <div className="space-y-3">
              {report.mentions.map((mention) => {
                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
                return (
                  <div key={mention.id} className="bg-black/20 border border-[var(--border-subtle)] rounded-2xl p-4">
                    <div className="flex items-center gap-3 mb-3">
                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-500'}`}>
                        {mention.aiEngine}
                      </span>
                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
                      </span>
                      <span className="text-xs text-[var(--text-disabled)] bg-white/[0.03] px-2 py-0.5 rounded">{mention.mentionType}</span>
                    </div>
                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recommendations */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
            <div className="space-y-2">
              {report.recommendations.map((rec, i) => (
                <div key={i} className="flex items-start gap-3 py-2">
                  <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-white/[0.06] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                  </div>
                  <p className="text-sm text-gray-300">{rec}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reputation;

import React, { useState } from 'react';
import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
import { scanReputation, generateReputationResponse } from '../services/reputation_service';
import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const AI_LOGOS: Record<string, string> = {
  ChatGPT: 'bg-purple-500/20 text-purple-300',
  Perplexity: 'bg-blue-500/20 text-blue-400',
  Claude: 'bg-orange-500/20 text-orange-400',
  Gemini: 'bg-purple-500/20 text-purple-400',
  Copilot: 'bg-cyan-500/20 text-cyan-400',
  'AI Overviews': 'bg-rose-500/20 text-rose-400',
};

const SEVERITY_CONFIG = {
  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-white/[0.06]' },
  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
};

const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const SENTIMENT_CONFIG = {
    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: 'Positif' },
    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Négatif' },
  };

  const [step, setStep] = useState<'form' | 'results'>('form');
  const [isScanning, setIsScanning] = useState(false);
  const [report, setReport] = useState<ReputationReport | null>(null);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [competitorInput, setCompetitorInput] = useState('');
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [keywordInput, setKeywordInput] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  // Action plan
  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [copied, setCopied] = useState(false);

  const addCompetitor = () => {
    if (competitorInput.trim() && competitors.length < 5) {
      setCompetitors([...competitors, competitorInput.trim()]);
      setCompetitorInput('');
    }
  };

  const addKeyword = () => {
    if (keywordInput.trim() && keywords.length < 10) {
      setKeywords([...keywords, keywordInput.trim()]);
      setKeywordInput('');
    }
  };

  const handleScan = async () => {
    if (!brandName || !industry) {
      alert('Veuillez remplir le nom de la marque et le secteur.');
      return;
    }

    const canProceed = onDeductCredits(3);
    if (!canProceed) return;

    setIsScanning(true);
    try {
      const result = await scanReputation({
        brandName,
        brandUrl: brandUrl || undefined,
        competitors: competitors.length > 0 ? competitors : undefined,
        industry,
        keywords: keywords.length > 0 ? keywords : undefined,
      }, 'fr');
      setReport(result);
      setStep('results');
    } catch (error) {
      console.error(error);
      alert('Erreur lors du scan.');
    } finally {
      setIsScanning(false);
    }
  };

  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
    setExpandedAlert(index);
    setIsGeneratingPlan(true);
    setActionPlan(null);
    try {
      const plan = await generateReputationResponse(alert, brandName, 'fr');
      setActionPlan(plan);
    } catch (e) {
      setActionPlan("Erreur lors de la génération du plan d'action.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Sentiment Gauge
  const SentimentGauge = ({ value }: { value: number }) => {
    const normalized = (value + 100) / 200;
    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
    return (
      <div className="w-full">
        <div className="flex justify-between text-xs text-gray-500 mb-1">
          <span>-100</span><span>0</span><span>+100</span>
        </div>
        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
        </div>
        <div className="text-center mt-2">
          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
          <span className="text-xs text-gray-500 ml-1">sentiment</span>
        </div>
      </div>
    );
  };

  // Score Ring
  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 36;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="flex flex-col items-center">
        <div className="relative w-24 h-24">
          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-2xl font-bold text-white">{score}</span>
          </div>
        </div>
        <span className="text-xs text-gray-500 mt-2">{label}</span>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-purple-500/10 rounded-2xl">
          <Shield size={32} className="text-purple-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">Réputation IA</h1>
          <p className="text-gray-500">Indice de visibilité & sentiment dans les réponses IA</p>
        </div>
        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-white/[0.06]">
          INDICE HEURISTIQUE
        </span>
      </div>

      {/* Form */}
      {step === 'form' && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">Nom de la marque *</label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">URL du site (optionnel)</label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">Secteur d'activité *</label>
            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
          </div>

          {/* Competitors */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.competitors}</label>
            <div className="flex gap-2">
              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder={t.reputation.addCompetitor} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addCompetitor} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {competitors.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {competitors.map((c, i) => (
                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Keywords */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.keywords}</label>
            <div className="flex gap-2">
              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addKeyword} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {keywords.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {keywords.map((k, i) => (
                  <span key={i} className="flex items-center gap-1 bg-white/[0.03] text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-4 text-sm text-gray-500">
            <div className="flex items-start gap-2">
              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
              <p>{t.reputation.heuristicBadge} — 3 GTO Gas</p>
            </div>
          </div>

          <button
            onClick={handleScan}
            disabled={isScanning || !brandName || !industry}
            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
          </button>
        </div>
      )}

      {/* Results */}
      {step === 'results' && report && (
        <div className="space-y-6">
          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>

          {/* Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 flex flex-col items-center">
              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <SentimentGauge value={report.overallSentiment} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h4 className="text-sm font-bold text-gray-500 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
              <div className="space-y-3">
                {(['positive', 'neutral', 'negative'] as const).map(s => {
                  const count = report.sentimentBreakdown[s];
                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
                  const cfg = SENTIMENT_CONFIG[s];
                  return (
                    <div key={s}>
                      <div className="flex justify-between text-xs mb-1">
                        <span className={cfg.color}>{cfg.label}</span>
                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
                      </div>
                      <div className="h-2 bg-white/[0.03] rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Top Themes */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
            <div className="flex flex-wrap gap-2">
              {report.topThemes.map((theme, i) => {
                const cfg = SENTIMENT_CONFIG[theme.sentiment];
                return (
                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
                    {theme.theme} ({theme.count})
                  </span>
                );
              })}
            </div>
          </div>

          {/* Competitor Comparison */}
          {report.competitorComparison && report.competitorComparison.length > 0 && (
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-[var(--border-subtle)]">
                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-[var(--border-subtle)] bg-white/[0.03]">
                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
                      <td className="py-3 text-center">
                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
                        </span>
                      </td>
                    </tr>
                    {report.competitorComparison.map((c, i) => (
                      <tr key={i} className="border-b border-[var(--border-subtle)]">
                        <td className="py-3 text-gray-300">{c.name}</td>
                        <td className="py-3 text-center text-white">{c.mentions}</td>
                        <td className="py-3 text-center">
                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Alerts */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
            <div className="space-y-3">
              {report.alerts.map((alert, i) => {
                const cfg = SEVERITY_CONFIG[alert.severity];
                const SevIcon = cfg.icon;
                const isExpanded = expandedAlert === i;
                return (
                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4`}>
                    <div className="flex items-start gap-3">
                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{alert.message}</p>
                        <p className="text-xs text-gray-500 mt-1">Action : {alert.action}</p>
                      </div>
                      <button
                        onClick={() => handleGenerateActionPlan(alert, i)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
                      >
                        <Sparkles size={12} /> {t.reputation.actionPlan}
                      </button>
                    </div>
                    {isExpanded && (
                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        {isGeneratingPlan ? (
                          <div className="flex items-center gap-2 text-sm text-gray-500"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
                        ) : actionPlan ? (
                          <div>
                            <div className="flex justify-end mb-2">
                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
                              </button>
                            </div>
                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
                          </div>
                        ) : null}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Mentions */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
            <div className="space-y-3">
              {report.mentions.map((mention) => {
                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
                return (
                  <div key={mention.id} className="bg-black/20 border border-[var(--border-subtle)] rounded-2xl p-4">
                    <div className="flex items-center gap-3 mb-3">
                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-500'}`}>
                        {mention.aiEngine}
                      </span>
                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
                      </span>
                      <span className="text-xs text-[var(--text-disabled)] bg-white/[0.03] px-2 py-0.5 rounded">{mention.mentionType}</span>
                    </div>
                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recommendations */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
            <div className="space-y-2">
              {report.recommendations.map((rec, i) => (
                <div key={i} className="flex items-start gap-3 py-2">
                  <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-white/[0.06] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                  </div>
                  <p className="text-sm text-gray-300">{rec}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reputation;

import React, { useState } from 'react';
import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
import { scanReputation, generateReputationResponse } from '../services/reputation_service';
import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const AI_LOGOS: Record<string, string> = {
  ChatGPT: 'bg-purple-500/20 text-purple-300',
  Perplexity: 'bg-blue-500/20 text-blue-400',
  Claude: 'bg-orange-500/20 text-orange-400',
  Gemini: 'bg-purple-500/20 text-purple-400',
  Copilot: 'bg-cyan-500/20 text-cyan-400',
  'AI Overviews': 'bg-rose-500/20 text-rose-400',
};

const SEVERITY_CONFIG = {
  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-white/[0.06]' },
  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
};

const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const SENTIMENT_CONFIG = {
    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: 'Positif' },
    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Négatif' },
  };

  const [step, setStep] = useState<'form' | 'results'>('form');
  const [isScanning, setIsScanning] = useState(false);
  const [report, setReport] = useState<ReputationReport | null>(null);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [competitorInput, setCompetitorInput] = useState('');
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [keywordInput, setKeywordInput] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  // Action plan
  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [copied, setCopied] = useState(false);

  const addCompetitor = () => {
    if (competitorInput.trim() && competitors.length < 5) {
      setCompetitors([...competitors, competitorInput.trim()]);
      setCompetitorInput('');
    }
  };

  const addKeyword = () => {
    if (keywordInput.trim() && keywords.length < 10) {
      setKeywords([...keywords, keywordInput.trim()]);
      setKeywordInput('');
    }
  };

  const handleScan = async () => {
    if (!brandName || !industry) {
      alert('Veuillez remplir le nom de la marque et le secteur.');
      return;
    }

    const canProceed = onDeductCredits(3);
    if (!canProceed) return;

    setIsScanning(true);
    try {
      const result = await scanReputation({
        brandName,
        brandUrl: brandUrl || undefined,
        competitors: competitors.length > 0 ? competitors : undefined,
        industry,
        keywords: keywords.length > 0 ? keywords : undefined,
      }, 'fr');
      setReport(result);
      setStep('results');
    } catch (error) {
      console.error(error);
      alert('Erreur lors du scan.');
    } finally {
      setIsScanning(false);
    }
  };

  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
    setExpandedAlert(index);
    setIsGeneratingPlan(true);
    setActionPlan(null);
    try {
      const plan = await generateReputationResponse(alert, brandName, 'fr');
      setActionPlan(plan);
    } catch (e) {
      setActionPlan("Erreur lors de la génération du plan d'action.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Sentiment Gauge
  const SentimentGauge = ({ value }: { value: number }) => {
    const normalized = (value + 100) / 200;
    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
    return (
      <div className="w-full">
        <div className="flex justify-between text-xs text-gray-500 mb-1">
          <span>-100</span><span>0</span><span>+100</span>
        </div>
        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
        </div>
        <div className="text-center mt-2">
          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
          <span className="text-xs text-gray-500 ml-1">sentiment</span>
        </div>
      </div>
    );
  };

  // Score Ring
  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 36;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="flex flex-col items-center">
        <div className="relative w-24 h-24">
          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-2xl font-bold text-white">{score}</span>
          </div>
        </div>
        <span className="text-xs text-gray-500 mt-2">{label}</span>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-purple-500/10 rounded-2xl">
          <Shield size={32} className="text-purple-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">Réputation IA</h1>
          <p className="text-gray-500">Indice de visibilité & sentiment dans les réponses IA</p>
        </div>
        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-white/[0.06]">
          INDICE HEURISTIQUE
        </span>
      </div>

      {/* Form */}
      {step === 'form' && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">Nom de la marque *</label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">URL du site (optionnel)</label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">Secteur d'activité *</label>
            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
          </div>

          {/* Competitors */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">Concurrents (max 5)</label>
            <div className="flex gap-2">
              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder={t.reputation.addCompetitor} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addCompetitor} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {competitors.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {competitors.map((c, i) => (
                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Keywords */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.keywords}</label>
            <div className="flex gap-2">
              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addKeyword} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {keywords.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {keywords.map((k, i) => (
                  <span key={i} className="flex items-center gap-1 bg-white/[0.03] text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-4 text-sm text-gray-500">
            <div className="flex items-start gap-2">
              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
              <p>{t.reputation.heuristicBadge} — 3 GTO Gas</p>
            </div>
          </div>

          <button
            onClick={handleScan}
            disabled={isScanning || !brandName || !industry}
            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
          </button>
        </div>
      )}

      {/* Results */}
      {step === 'results' && report && (
        <div className="space-y-6">
          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>

          {/* Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 flex flex-col items-center">
              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <SentimentGauge value={report.overallSentiment} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h4 className="text-sm font-bold text-gray-500 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
              <div className="space-y-3">
                {(['positive', 'neutral', 'negative'] as const).map(s => {
                  const count = report.sentimentBreakdown[s];
                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
                  const cfg = SENTIMENT_CONFIG[s];
                  return (
                    <div key={s}>
                      <div className="flex justify-between text-xs mb-1">
                        <span className={cfg.color}>{cfg.label}</span>
                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
                      </div>
                      <div className="h-2 bg-white/[0.03] rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Top Themes */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
            <div className="flex flex-wrap gap-2">
              {report.topThemes.map((theme, i) => {
                const cfg = SENTIMENT_CONFIG[theme.sentiment];
                return (
                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
                    {theme.theme} ({theme.count})
                  </span>
                );
              })}
            </div>
          </div>

          {/* Competitor Comparison */}
          {report.competitorComparison && report.competitorComparison.length > 0 && (
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-[var(--border-subtle)]">
                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-[var(--border-subtle)] bg-white/[0.03]">
                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
                      <td className="py-3 text-center">
                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
                        </span>
                      </td>
                    </tr>
                    {report.competitorComparison.map((c, i) => (
                      <tr key={i} className="border-b border-[var(--border-subtle)]">
                        <td className="py-3 text-gray-300">{c.name}</td>
                        <td className="py-3 text-center text-white">{c.mentions}</td>
                        <td className="py-3 text-center">
                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Alerts */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
            <div className="space-y-3">
              {report.alerts.map((alert, i) => {
                const cfg = SEVERITY_CONFIG[alert.severity];
                const SevIcon = cfg.icon;
                const isExpanded = expandedAlert === i;
                return (
                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4`}>
                    <div className="flex items-start gap-3">
                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{alert.message}</p>
                        <p className="text-xs text-gray-500 mt-1">Action : {alert.action}</p>
                      </div>
                      <button
                        onClick={() => handleGenerateActionPlan(alert, i)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
                      >
                        <Sparkles size={12} /> {t.reputation.actionPlan}
                      </button>
                    </div>
                    {isExpanded && (
                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        {isGeneratingPlan ? (
                          <div className="flex items-center gap-2 text-sm text-gray-500"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
                        ) : actionPlan ? (
                          <div>
                            <div className="flex justify-end mb-2">
                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
                              </button>
                            </div>
                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
                          </div>
                        ) : null}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Mentions */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
            <div className="space-y-3">
              {report.mentions.map((mention) => {
                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
                return (
                  <div key={mention.id} className="bg-black/20 border border-[var(--border-subtle)] rounded-2xl p-4">
                    <div className="flex items-center gap-3 mb-3">
                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-500'}`}>
                        {mention.aiEngine}
                      </span>
                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
                      </span>
                      <span className="text-xs text-[var(--text-disabled)] bg-white/[0.03] px-2 py-0.5 rounded">{mention.mentionType}</span>
                    </div>
                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recommendations */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
            <div className="space-y-2">
              {report.recommendations.map((rec, i) => (
                <div key={i} className="flex items-start gap-3 py-2">
                  <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-white/[0.06] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                  </div>
                  <p className="text-sm text-gray-300">{rec}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reputation;

import React, { useState } from 'react';
import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
import { scanReputation, generateReputationResponse } from '../services/reputation_service';
import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const AI_LOGOS: Record<string, string> = {
  ChatGPT: 'bg-purple-500/20 text-purple-300',
  Perplexity: 'bg-blue-500/20 text-blue-400',
  Claude: 'bg-orange-500/20 text-orange-400',
  Gemini: 'bg-purple-500/20 text-purple-400',
  Copilot: 'bg-cyan-500/20 text-cyan-400',
  'AI Overviews': 'bg-rose-500/20 text-rose-400',
};

const SEVERITY_CONFIG = {
  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-white/[0.06]' },
  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
};

const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const SENTIMENT_CONFIG = {
    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: 'Positif' },
    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Négatif' },
  };

  const [step, setStep] = useState<'form' | 'results'>('form');
  const [isScanning, setIsScanning] = useState(false);
  const [report, setReport] = useState<ReputationReport | null>(null);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [competitorInput, setCompetitorInput] = useState('');
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [keywordInput, setKeywordInput] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  // Action plan
  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [copied, setCopied] = useState(false);

  const addCompetitor = () => {
    if (competitorInput.trim() && competitors.length < 5) {
      setCompetitors([...competitors, competitorInput.trim()]);
      setCompetitorInput('');
    }
  };

  const addKeyword = () => {
    if (keywordInput.trim() && keywords.length < 10) {
      setKeywords([...keywords, keywordInput.trim()]);
      setKeywordInput('');
    }
  };

  const handleScan = async () => {
    if (!brandName || !industry) {
      alert('Veuillez remplir le nom de la marque et le secteur.');
      return;
    }

    const canProceed = onDeductCredits(3);
    if (!canProceed) return;

    setIsScanning(true);
    try {
      const result = await scanReputation({
        brandName,
        brandUrl: brandUrl || undefined,
        competitors: competitors.length > 0 ? competitors : undefined,
        industry,
        keywords: keywords.length > 0 ? keywords : undefined,
      }, 'fr');
      setReport(result);
      setStep('results');
    } catch (error) {
      console.error(error);
      alert('Erreur lors du scan.');
    } finally {
      setIsScanning(false);
    }
  };

  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
    setExpandedAlert(index);
    setIsGeneratingPlan(true);
    setActionPlan(null);
    try {
      const plan = await generateReputationResponse(alert, brandName, 'fr');
      setActionPlan(plan);
    } catch (e) {
      setActionPlan("Erreur lors de la génération du plan d'action.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Sentiment Gauge
  const SentimentGauge = ({ value }: { value: number }) => {
    const normalized = (value + 100) / 200;
    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
    return (
      <div className="w-full">
        <div className="flex justify-between text-xs text-gray-500 mb-1">
          <span>-100</span><span>0</span><span>+100</span>
        </div>
        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
        </div>
        <div className="text-center mt-2">
          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
          <span className="text-xs text-gray-500 ml-1">sentiment</span>
        </div>
      </div>
    );
  };

  // Score Ring
  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 36;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="flex flex-col items-center">
        <div className="relative w-24 h-24">
          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-2xl font-bold text-white">{score}</span>
          </div>
        </div>
        <span className="text-xs text-gray-500 mt-2">{label}</span>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-purple-500/10 rounded-2xl">
          <Shield size={32} className="text-purple-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">Réputation IA</h1>
          <p className="text-gray-500">Indice de visibilité & sentiment dans les réponses IA</p>
        </div>
        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-white/[0.06]">
          INDICE HEURISTIQUE
        </span>
      </div>

      {/* Form */}
      {step === 'form' && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">Nom de la marque *</label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">URL du site (optionnel)</label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">Secteur d'activité *</label>
            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
          </div>

          {/* Competitors */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">Concurrents (max 5)</label>
            <div className="flex gap-2">
              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder="Ajouter un concurrent..." className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addCompetitor} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {competitors.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {competitors.map((c, i) => (
                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Keywords */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">{t.reputation.keywords}</label>
            <div className="flex gap-2">
              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addKeyword} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {keywords.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {keywords.map((k, i) => (
                  <span key={i} className="flex items-center gap-1 bg-white/[0.03] text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-4 text-sm text-gray-500">
            <div className="flex items-start gap-2">
              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
              <p>{t.reputation.heuristicBadge} — 3 GTO Gas</p>
            </div>
          </div>

          <button
            onClick={handleScan}
            disabled={isScanning || !brandName || !industry}
            className="w-full bg-gradient-to-r from-purple-500 to-violet-600 text-white font-bold py-3.5 rounded-2xl hover:from-purple-600 hover:to-violet-700 transition-colors flex items-center justify-center gap-2 disabled:opacity-50 disabled:cursor-not-allowed"
          >
            {isScanning ? <><Loader2 size={18} className="animate-spin" /> {t.reputation.scanning}</> : <><Shield size={18} /> {t.reputation.launchScan}</>}
          </button>
        </div>
      )}

      {/* Results */}
      {step === 'results' && report && (
        <div className="space-y-6">
          <button onClick={() => setStep('form')} className="text-sm text-gray-500 hover:text-white">&larr; {t.common.back}</button>

          {/* Dashboard Cards */}
          <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 flex flex-col items-center">
              <ScoreRing score={report.visibilityScore} label={t.reputation.aiVisibility} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <SentimentGauge value={report.overallSentiment} />
            </div>
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h4 className="text-sm font-bold text-gray-500 mb-4">{t.reputation.breakdown} ({report.totalMentions} mentions)</h4>
              <div className="space-y-3">
                {(['positive', 'neutral', 'negative'] as const).map(s => {
                  const count = report.sentimentBreakdown[s];
                  const pct = report.totalMentions > 0 ? (count / report.totalMentions) * 100 : 0;
                  const cfg = SENTIMENT_CONFIG[s];
                  return (
                    <div key={s}>
                      <div className="flex justify-between text-xs mb-1">
                        <span className={cfg.color}>{cfg.label}</span>
                        <span className="text-gray-500">{count} ({Math.round(pct)}%)</span>
                      </div>
                      <div className="h-2 bg-white/[0.03] rounded-full overflow-hidden">
                        <div className={`h-full rounded-full ${s === 'positive' ? 'bg-purple-400' : s === 'neutral' ? 'bg-gray-500' : 'bg-red-500'}`} style={{ width: `${pct}%` }} />
                      </div>
                    </div>
                  );
                })}
              </div>
            </div>
          </div>

          {/* Top Themes */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Target size={16} className="text-purple-400" /> {t.reputation.dominantThemes}</h3>
            <div className="flex flex-wrap gap-2">
              {report.topThemes.map((theme, i) => {
                const cfg = SENTIMENT_CONFIG[theme.sentiment];
                return (
                  <span key={i} className={`${cfg.bg} ${cfg.color} text-xs font-medium px-3 py-1.5 rounded-full border ${cfg.border}`}>
                    {theme.theme} ({theme.count})
                  </span>
                );
              })}
            </div>
          </div>

          {/* Competitor Comparison */}
          {report.competitorComparison && report.competitorComparison.length > 0 && (
            <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
              <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><BarChart3 size={16} className="text-purple-400" /> {t.reputation.competitorComparison}</h3>
              <div className="overflow-x-auto">
                <table className="w-full text-sm">
                  <thead>
                    <tr className="border-b border-[var(--border-subtle)]">
                      <th className="text-left py-2 text-gray-500 font-medium">{locale === 'en' ? 'Brand' : locale === 'es' ? 'Marca' : 'Marque'}</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Mentions</th>
                      <th className="text-center py-2 text-gray-500 font-medium">Sentiment</th>
                    </tr>
                  </thead>
                  <tbody>
                    <tr className="border-b border-[var(--border-subtle)] bg-white/[0.03]">
                      <td className="py-3 font-bold text-purple-400">{report.brandName} ({locale === 'en' ? 'you' : locale === 'es' ? 'usted' : 'vous'})</td>
                      <td className="py-3 text-center text-white">{report.totalMentions}</td>
                      <td className="py-3 text-center">
                        <span className={report.overallSentiment > 0 ? 'text-purple-300' : report.overallSentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                          {report.overallSentiment > 0 ? '+' : ''}{report.overallSentiment}
                        </span>
                      </td>
                    </tr>
                    {report.competitorComparison.map((c, i) => (
                      <tr key={i} className="border-b border-[var(--border-subtle)]">
                        <td className="py-3 text-gray-300">{c.name}</td>
                        <td className="py-3 text-center text-white">{c.mentions}</td>
                        <td className="py-3 text-center">
                          <span className={c.sentiment > 0 ? 'text-purple-300' : c.sentiment < 0 ? 'text-red-400' : 'text-gray-500'}>
                            {c.sentiment > 0 ? '+' : ''}{c.sentiment}
                          </span>
                        </td>
                      </tr>
                    ))}
                  </tbody>
                </table>
              </div>
            </div>
          )}

          {/* Alerts */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><AlertTriangle size={16} className="text-purple-400" /> {t.reputation.alerts}</h3>
            <div className="space-y-3">
              {report.alerts.map((alert, i) => {
                const cfg = SEVERITY_CONFIG[alert.severity];
                const SevIcon = cfg.icon;
                const isExpanded = expandedAlert === i;
                return (
                  <div key={i} className={`${cfg.bg} border ${cfg.border} rounded-2xl p-4`}>
                    <div className="flex items-start gap-3">
                      <SevIcon size={18} className={`${cfg.color} flex-shrink-0 mt-0.5`} />
                      <div className="flex-1">
                        <p className="text-sm text-gray-200">{alert.message}</p>
                        <p className="text-xs text-gray-500 mt-1">Action : {alert.action}</p>
                      </div>
                      <button
                        onClick={() => handleGenerateActionPlan(alert, i)}
                        className={`text-xs px-3 py-1.5 rounded-full border transition-colors flex items-center gap-1 flex-shrink-0 ${cfg.border} ${cfg.color} hover:bg-purple-500/10`}
                      >
                        <Sparkles size={12} /> {t.reputation.actionPlan}
                      </button>
                    </div>
                    {isExpanded && (
                      <div className="mt-4 pt-4 border-t border-[var(--border-subtle)]">
                        {isGeneratingPlan ? (
                          <div className="flex items-center gap-2 text-sm text-gray-500"><Loader2 size={14} className="animate-spin" /> {t.common.loading}</div>
                        ) : actionPlan ? (
                          <div>
                            <div className="flex justify-end mb-2">
                              <button onClick={() => handleCopy(actionPlan)} className="text-xs text-gray-500 hover:text-white flex items-center gap-1">
                                {copied ? <Check size={12} /> : <Copy size={12} />} {t.common.copy}
                              </button>
                            </div>
                            <div className="prose prose-invert prose-sm max-w-none whitespace-pre-wrap text-gray-300 text-xs leading-relaxed">{actionPlan}</div>
                          </div>
                        ) : null}
                      </div>
                    )}
                  </div>
                );
              })}
            </div>
          </div>

          {/* Mentions */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><Bot size={16} className="text-purple-400" /> {t.reputation.simulatedMentions}</h3>
            <div className="space-y-3">
              {report.mentions.map((mention) => {
                const sentCfg = SENTIMENT_CONFIG[mention.sentiment];
                return (
                  <div key={mention.id} className="bg-black/20 border border-[var(--border-subtle)] rounded-2xl p-4">
                    <div className="flex items-center gap-3 mb-3">
                      <span className={`text-xs font-bold px-2.5 py-1 rounded-full ${AI_LOGOS[mention.aiEngine] || 'bg-gray-500/20 text-gray-500'}`}>
                        {mention.aiEngine}
                      </span>
                      <span className={`text-xs px-2 py-0.5 rounded-full ${sentCfg.bg} ${sentCfg.color} border ${sentCfg.border}`}>
                        {mention.sentimentScore > 0 ? '+' : ''}{mention.sentimentScore} {sentCfg.label}
                      </span>
                      <span className="text-xs text-[var(--text-disabled)] bg-white/[0.03] px-2 py-0.5 rounded">{mention.mentionType}</span>
                    </div>
                    <p className="text-xs text-gray-500 mb-1.5">Prompt : "{mention.prompt}"</p>
                    <p className="text-sm text-gray-300 italic">"{mention.excerpt}"</p>
                    <p className="text-xs text-gray-500 mt-2">{mention.context}</p>
                  </div>
                );
              })}
            </div>
          </div>

          {/* Recommendations */}
          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6">
            <h3 className="text-sm font-bold text-gray-200 mb-4 flex items-center gap-2"><TrendingUp size={16} className="text-purple-400" /> {t.reputation.recommendations}</h3>
            <div className="space-y-2">
              {report.recommendations.map((rec, i) => (
                <div key={i} className="flex items-start gap-3 py-2">
                  <div className="w-6 h-6 rounded-full bg-purple-500/10 border border-white/[0.06] flex items-center justify-center flex-shrink-0 mt-0.5">
                    <span className="text-xs font-bold text-purple-400">{i + 1}</span>
                  </div>
                  <p className="text-sm text-gray-300">{rec}</p>
                </div>
              ))}
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Reputation;

import React, { useState } from 'react';
import { User, ReputationScanInput, ReputationReport, AIMention } from '../types';
import { scanReputation, generateReputationResponse } from '../services/reputation_service';
import { ArrowLeft, Shield, Loader2, AlertTriangle, AlertCircle, Info, TrendingUp, TrendingDown, Minus, Copy, Check, Download, ChevronDown, ChevronRight, Sparkles, Search, X, Plus, Bot, Eye, MessageSquare, BarChart3, Target } from 'lucide-react';
import PageHeader from '../components/layout/PageHeader';

interface Props {
  onBack: () => void;
  user: User | null;
  onDeductCredits: (amount: number) => boolean;
}

const AI_LOGOS: Record<string, string> = {
  ChatGPT: 'bg-purple-500/20 text-purple-300',
  Perplexity: 'bg-blue-500/20 text-blue-400',
  Claude: 'bg-orange-500/20 text-orange-400',
  Gemini: 'bg-purple-500/20 text-purple-400',
  Copilot: 'bg-cyan-500/20 text-cyan-400',
  'AI Overviews': 'bg-rose-500/20 text-rose-400',
};

const SEVERITY_CONFIG = {
  critical: { icon: AlertTriangle, color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20' },
  warning: { icon: AlertCircle, color: 'text-purple-400', bg: 'bg-purple-500/10', border: 'border-white/[0.06]' },
  info: { icon: Info, color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20' },
};

const Reputation: React.FC<Props> = ({ onBack, user, onDeductCredits }) => {
  const SENTIMENT_CONFIG = {
    positive: { color: 'text-purple-300', bg: 'bg-purple-500/10', border: 'border-white/[0.06]', label: 'Positif' },
    neutral: { color: 'text-gray-500', bg: 'bg-gray-500/10', border: 'border-gray-500/20', label: 'Neutre' },
    negative: { color: 'text-red-400', bg: 'bg-red-500/10', border: 'border-red-500/20', label: 'Négatif' },
  };

  const [step, setStep] = useState<'form' | 'results'>('form');
  const [isScanning, setIsScanning] = useState(false);
  const [report, setReport] = useState<ReputationReport | null>(null);

  // Form
  const [brandName, setBrandName] = useState('');
  const [brandUrl, setBrandUrl] = useState('');
  const [industry, setIndustry] = useState('');
  const [competitorInput, setCompetitorInput] = useState('');
  const [competitors, setCompetitors] = useState<string[]>([]);
  const [keywordInput, setKeywordInput] = useState('');
  const [keywords, setKeywords] = useState<string[]>([]);

  // Action plan
  const [expandedAlert, setExpandedAlert] = useState<number | null>(null);
  const [actionPlan, setActionPlan] = useState<string | null>(null);
  const [isGeneratingPlan, setIsGeneratingPlan] = useState(false);
  const [copied, setCopied] = useState(false);

  const addCompetitor = () => {
    if (competitorInput.trim() && competitors.length < 5) {
      setCompetitors([...competitors, competitorInput.trim()]);
      setCompetitorInput('');
    }
  };

  const addKeyword = () => {
    if (keywordInput.trim() && keywords.length < 10) {
      setKeywords([...keywords, keywordInput.trim()]);
      setKeywordInput('');
    }
  };

  const handleScan = async () => {
    if (!brandName || !industry) {
      alert('Veuillez remplir le nom de la marque et le secteur.');
      return;
    }

    const canProceed = onDeductCredits(3);
    if (!canProceed) return;

    setIsScanning(true);
    try {
      const result = await scanReputation({
        brandName,
        brandUrl: brandUrl || undefined,
        competitors: competitors.length > 0 ? competitors : undefined,
        industry,
        keywords: keywords.length > 0 ? keywords : undefined,
      }, 'fr');
      setReport(result);
      setStep('results');
    } catch (error) {
      console.error(error);
      alert('Erreur lors du scan.');
    } finally {
      setIsScanning(false);
    }
  };

  const handleGenerateActionPlan = async (alert: { message: string; action: string }, index: number) => {
    setExpandedAlert(index);
    setIsGeneratingPlan(true);
    setActionPlan(null);
    try {
      const plan = await generateReputationResponse(alert, brandName, 'fr');
      setActionPlan(plan);
    } catch (e) {
      setActionPlan("Erreur lors de la génération du plan d'action.");
    } finally {
      setIsGeneratingPlan(false);
    }
  };

  const handleCopy = (text: string) => {
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  // Sentiment Gauge
  const SentimentGauge = ({ value }: { value: number }) => {
    const normalized = (value + 100) / 200;
    const color = value > 30 ? '#a855f7' : value > -10 ? '#c084fc' : '#ef4444';
    return (
      <div className="w-full">
        <div className="flex justify-between text-xs text-gray-500 mb-1">
          <span>-100</span><span>0</span><span>+100</span>
        </div>
        <div className="h-3 bg-gradient-to-r from-red-500/30 via-purple-500/30 to-purple-400/30 rounded-full overflow-hidden relative">
          <div className="absolute top-0 bottom-0 w-1 bg-white rounded-full shadow-lg" style={{ left: `${normalized * 100}%`, transform: 'translateX(-50%)' }} />
        </div>
        <div className="text-center mt-2">
          <span className="text-2xl font-bold" style={{ color }}>{value > 0 ? '+' : ''}{value}</span>
          <span className="text-xs text-gray-500 ml-1">sentiment</span>
        </div>
      </div>
    );
  };

  // Score Ring
  const ScoreRing = ({ score, label }: { score: number; label: string }) => {
    const color = score >= 60 ? '#a855f7' : score >= 35 ? '#c084fc' : '#ef4444';
    const circumference = 2 * Math.PI * 36;
    const offset = circumference - (score / 100) * circumference;
    return (
      <div className="flex flex-col items-center">
        <div className="relative w-24 h-24">
          <svg className="w-24 h-24 -rotate-90" viewBox="0 0 80 80">
            <circle cx="40" cy="40" r="36" fill="none" stroke="rgba(255,255,255,0.05)" strokeWidth="5" />
            <circle cx="40" cy="40" r="36" fill="none" stroke={color} strokeWidth="5" strokeDasharray={circumference} strokeDashoffset={offset} strokeLinecap="round" />
          </svg>
          <div className="absolute inset-0 flex items-center justify-center">
            <span className="text-2xl font-bold text-white">{score}</span>
          </div>
        </div>
        <span className="text-xs text-gray-500 mt-2">{label}</span>
      </div>
    );
  };

  return (
    <div className="page-enter">
      <PageHeader title="Réputation" description="Analyse de votre e-réputation dans les IA" />

      {/* Header */}
      <div className="flex items-center gap-4 mb-10">
        <div className="p-3 bg-purple-500/10 rounded-2xl">
          <Shield size={32} className="text-purple-400" />
        </div>
        <div>
          <h1 className="text-3xl font-bold text-white">Réputation IA</h1>
          <p className="text-gray-500">Indice de visibilité & sentiment dans les réponses IA</p>
        </div>
        <span className="ml-auto bg-purple-500/10 text-purple-400 text-[10px] font-bold px-3 py-1 rounded-full border border-white/[0.06]">
          INDICE HEURISTIQUE
        </span>
      </div>

      {/* Form */}
      {step === 'form' && (
        <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-6 space-y-5">
          <div className="grid grid-cols-1 md:grid-cols-2 gap-5">
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">Nom de la marque *</label>
              <input value={brandName} onChange={e => setBrandName(e.target.value)} placeholder="Ex: CitedBy.ai" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
            <div>
              <label className="block text-sm text-gray-500 mb-1.5">URL du site (optionnel)</label>
              <input value={brandUrl} onChange={e => setBrandUrl(e.target.value)} placeholder="https://example.com" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
            </div>
          </div>
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">Secteur d'activité *</label>
            <input value={industry} onChange={e => setIndustry(e.target.value)} placeholder="Ex: SaaS SEO, E-commerce" className="w-full bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
          </div>

          {/* Competitors */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">Concurrents (max 5)</label>
            <div className="flex gap-2">
              <input value={competitorInput} onChange={e => setCompetitorInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addCompetitor()} placeholder="Ajouter un concurrent..." className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addCompetitor} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {competitors.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {competitors.map((c, i) => (
                  <span key={i} className="flex items-center gap-1 bg-purple-500/10 text-purple-400 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {c} <button onClick={() => setCompetitors(competitors.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          {/* Keywords */}
          <div>
            <label className="block text-sm text-gray-500 mb-1.5">Mots-clés surveillés (max 10)</label>
            <div className="flex gap-2">
              <input value={keywordInput} onChange={e => setKeywordInput(e.target.value)} onKeyDown={e => e.key === 'Enter' && addKeyword()} placeholder={t.reputation.addKeyword} className="flex-1 bg-black/40 border border-white/[0.06] rounded-xl p-3 text-white focus:border-purple-500/50 outline-none text-sm" />
              <button onClick={addKeyword} className="px-4 bg-white/[0.03] border border-white/[0.06] rounded-full hover:bg-purple-500/10 transition-colors"><Plus size={16} className="text-gray-500" /></button>
            </div>
            {keywords.length > 0 && (
              <div className="flex flex-wrap gap-2 mt-2">
                {keywords.map((k, i) => (
                  <span key={i} className="flex items-center gap-1 bg-white/[0.03] text-gray-300 text-xs px-2.5 py-1 rounded-full border border-white/[0.06]">
                    {k} <button onClick={() => setKeywords(keywords.filter((_, idx) => idx !== i))}><X size={12} /></button>
                  </span>
                ))}
              </div>
            )}
          </div>

          <div className="bg-white/[0.03] border border-white/[0.06] rounded-2xl p-4 text-sm text-gray-500">
            <div className="flex items-start gap-2">
              <Info size={16} className="text-purple-400 mt-0.5 flex-shrink-0" />
